use super::{HighlightKind, VizFrame};
use rand::Rng;
use std::collections::{HashMap, HashSet, VecDeque};

/// Helper for building visualization frames from an array algorithm.
pub struct VizLog {
    array: Vec<i32>,
    frames: Vec<VizFrame>,
}

impl VizLog {
    pub fn new(array: Vec<i32>) -> Self {
        let mut log = Self {
            array: array.clone(),
            frames: Vec::new(),
        };
        log.frames.push(VizFrame {
            array,
            highlights: vec![],
            annotation: "Initial state".to_string(),
            ..Default::default()
        });
        log
    }

    #[allow(dead_code)]
    pub fn step(&mut self, highlights: &[(usize, HighlightKind)], annotation: impl Into<String>) {
        self.frames.push(VizFrame {
            array: self.array.clone(),
            highlights: highlights.to_vec(),
            annotation: annotation.into(),
            ..Default::default()
        });
    }

    /// Add a frame with named pointers (shown as labeled arrows below bars).
    pub fn ptrs(
        &mut self,
        highlights: &[(usize, HighlightKind)],
        pointers: &[(usize, &str)],
        annotation: impl Into<String>,
    ) {
        self.frames.push(VizFrame {
            array: self.array.clone(),
            data: None,
            highlights: highlights.to_vec(),
            pointers: pointers.iter().map(|(i, s)| (*i, s.to_string())).collect(),
            annotation: annotation.into(),
        });
    }

    pub fn swap(&mut self, i: usize, j: usize, annotation: impl Into<String>) {
        self.array.swap(i, j);
        self.frames.push(VizFrame {
            array: self.array.clone(),
            highlights: vec![(i, HighlightKind::Swapping), (j, HighlightKind::Swapping)],
            annotation: annotation.into(),
            ..Default::default()
        });
    }

    pub fn set(&mut self, i: usize, val: i32, annotation: impl Into<String>) {
        self.array[i] = val;
        self.frames.push(VizFrame {
            array: self.array.clone(),
            highlights: vec![(i, HighlightKind::Active)],
            annotation: annotation.into(),
            ..Default::default()
        });
    }

    pub fn done(&mut self, indices: &[usize], annotation: impl Into<String>) {
        self.frames.push(VizFrame {
            array: self.array.clone(),
            highlights: indices
                .iter()
                .map(|&i| (i, HighlightKind::Sorted))
                .collect(),
            annotation: annotation.into(),
            ..Default::default()
        });
    }

    pub fn finish(&mut self, annotation: impl Into<String>) {
        let n = self.array.len();
        self.done(&(0..n).collect::<Vec<_>>(), annotation);
    }

    pub fn into_frames(self) -> Vec<VizFrame> {
        self.frames
    }

    /// Convert all frames to use VizData::Tree (level-order array → tree nodes).
    pub fn into_tree_frames(self) -> Vec<VizFrame> {
        self.frames
            .into_iter()
            .map(|mut f| {
                f.data = Some(super::VizData::Tree {
                    nodes: f.array.iter().map(|v| Some(v.to_string())).collect(),
                });
                f
            })
            .collect()
    }

    /// Convert all frames to use VizData::Graph.
    /// Convert all frames to use VizData::Grid with given dimensions.
    pub fn into_grid_frames(self, rows: usize, cols: usize) -> Vec<VizFrame> {
        self.frames
            .into_iter()
            .map(|mut f| {
                let mut cells: Vec<Vec<String>> = Vec::new();
                for r in 0..rows {
                    let mut row = Vec::new();
                    for c in 0..cols {
                        let idx = r * cols + c;
                        if idx < f.array.len() {
                            row.push(f.array[idx].to_string());
                        } else {
                            row.push(" ".to_string());
                        }
                    }
                    cells.push(row);
                }
                f.data = Some(super::VizData::Grid { cells });
                f
            })
            .collect()
    }
}

