fn viz_merge_sort_merge_two_sorted() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let m = rng.random_range(3..=5);
    let n = rng.random_range(3..=5);
    let mut a = rand_arr(&mut rng, m, 1, 15);
    let mut b = rand_arr(&mut rng, n, 1, 15);
    a.sort();
    b.sort();
    let mut display = a.clone();
    display.extend(&b);

    let mut v = VizLog::new(display.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: merge two sorted arrays into one. Strategy: two pointers, always \
             take the smaller front element. {:?} + {:?}.",
            a, b
        ),
    );

    let mut result = Vec::new();
    let (mut i, mut j) = (0usize, 0usize);
    let mut out = 0usize;
    while i < m && j < n {
        v.ptrs(
            &[
                (i, HighlightKind::Comparing),
                (m + j, HighlightKind::Comparing),
            ],
            &[(i, "L"), (m + j, "R"), (out, "out")],
            format!("Compare {} vs {}", a[i], b[j]),
        );
        if a[i] <= b[j] {
            result.push(a[i]);
            display[out] = a[i];
            i += 1;
        } else {
            result.push(b[j]);
            display[out] = b[j];
            j += 1;
        }
        v.array = display.clone();
        out += 1;
    }
    while i < m {
        result.push(a[i]);
        display[out] = a[i];
        v.array = display.clone();
        v.ptrs(
            &[(out, HighlightKind::Active)],
            &[(out, "out")],
            format!("Copy remaining {}", a[i]),
        );
        i += 1;
        out += 1;
    }
    while j < n {
        result.push(b[j]);
        display[out] = b[j];
        v.array = display.clone();
        v.ptrs(
            &[(out, HighlightKind::Active)],
            &[(out, "out")],
            format!("Copy remaining {}", b[j]),
        );
        j += 1;
        out += 1;
    }
    let all: Vec<(usize, HighlightKind)> = (0..m + n).map(|x| (x, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[],
        format!("Answer: {:?}. O(n + m) — linear merge.", result),
    );
    v.into_frames()
}

fn viz_merge_sort_count_inversions() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        "Goal: count inversions (pairs i<j with nums[i]>nums[j]) using merge sort. \
         Strategy: during the merge step, when a right element is placed before left elements, \
         count the remaining left elements as inversions.",
    );

    let mut work = arr.clone();
    let mut inv_count = 0i32;
    // Iterative bottom-up merge sort counting inversions
    let mut width = 1;
    while width < n {
        let mut i = 0;
        while i < n {
            let left = i;
            let mid = (i + width).min(n);
            let right = (i + 2 * width).min(n);
            let left_half: Vec<i32> = work[left..mid].to_vec();
            let right_half: Vec<i32> = work[mid..right].to_vec();
            let (mut li, mut ri, mut k) = (0, 0, left);
            while li < left_half.len() && ri < right_half.len() {
                if left_half[li] <= right_half[ri] {
                    work[k] = left_half[li];
                    li += 1;
                } else {
                    work[k] = right_half[ri];
                    inv_count += (left_half.len() - li) as i32;
                    v.ptrs(
                        &[
                            (left + li, HighlightKind::Comparing),
                            (mid + ri, HighlightKind::Comparing),
                        ],
                        &[(left + li, "L"), (mid + ri, "R")],
                        format!(
                            "{} > {}, +{} inversions",
                            left_half[li],
                            right_half[ri],
                            left_half.len() - li
                        ),
                    );
                    ri += 1;
                }
                k += 1;
            }
            while li < left_half.len() {
                work[k] = left_half[li];
                li += 1;
                k += 1;
            }
            while ri < right_half.len() {
                work[k] = right_half[ri];
                ri += 1;
                k += 1;
            }
            v.array = work.clone();
            i += 2 * width;
        }
        width *= 2;
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|x| (x, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[],
        format!(
            "Answer: {} inversions. O(n log n) — merge sort approach.",
            inv_count
        ),
    );
    v.into_frames()
}

