fn viz_merge_sort_merge_sorted_arrays() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let k = 3;
    let sizes: Vec<usize> = (0..k).map(|_| rng.random_range(2..=3)).collect();
    let arrays: Vec<Vec<i32>> = sizes
        .iter()
        .map(|&s| {
            let mut a = rand_arr(&mut rng, s, 1, 15);
            a.sort();
            a
        })
        .collect();
    let mut flat: Vec<i32> = arrays.iter().flat_map(|a| a.iter().copied()).collect();
    let n = flat.len();

    let mut v = VizLog::new(flat.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: merge {} sorted arrays into one sorted array. Strategy: merge \
             arrays sequentially (pairwise). Optimal uses a min-heap for k-way merge.",
            k
        ),
    );

    // Merge all arrays together sequentially for visualization
    let mut result: Vec<i32> = arrays[0].clone();
    let mut offset = arrays[0].len();
    for other in arrays.iter().take(k).skip(1) {
        let mut merged = Vec::new();
        let (mut i, mut j) = (0, 0);
        while i < result.len() && j < other.len() {
            v.ptrs(
                &[
                    (i.min(n - 1), HighlightKind::Comparing),
                    ((offset + j).min(n - 1), HighlightKind::Comparing),
                ],
                &[(i.min(n - 1), "L"), ((offset + j).min(n - 1), "R")],
                format!("Merge: {} vs {}", result[i], other[j]),
            );
            if result[i] <= other[j] {
                merged.push(result[i]);
                i += 1;
            } else {
                merged.push(other[j]);
                j += 1;
            }
        }
        while i < result.len() {
            merged.push(result[i]);
            i += 1;
        }
        while j < other.len() {
            merged.push(other[j]);
            j += 1;
        }
        result = merged;
        offset += other.len();
    }

    // Show final sorted result
    for (i, &val) in result.iter().enumerate() {
        if i < n {
            flat[i] = val;
        }
    }
    v.array = flat;
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|x| (x, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[],
        format!(
            "Answer: {:?}. O(n log k) with heap, O(n*k) sequential.",
            result
        ),
    );
    v.into_frames()
}

