fn viz_merge_sort_smallest_range() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let k = 3;
    let lists: Vec<Vec<i32>> = (0..k)
        .map(|_| {
            let s = rng.random_range(2..=3);
            let mut a = rand_arr(&mut rng, s, 1, 20);
            a.sort();
            a
        })
        .collect();
    let flat: Vec<i32> = lists.iter().flat_map(|a| a.iter().copied()).collect();
    let n = flat.len();

    let mut v = VizLog::new(flat.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: find the smallest range that includes at least one element from each of \
             {} sorted lists. Strategy: merge all into sorted order with source tracking, \
             then use a sliding window to find the smallest window covering all lists.",
            k
        ),
    );

    // Merge all into sorted with source tracking
    let mut items: Vec<(i32, usize)> = Vec::new();
    for (li, list) in lists.iter().enumerate() {
        for &val in list {
            items.push((val, li));
        }
    }
    items.sort();

    let mut best_range = (0i32, i32::MAX);
    let mut counts = vec![0usize; k];
    let mut covered = 0usize;
    let mut left = 0usize;

    for right in 0..items.len() {
        let disp_r = right.min(n - 1);
        if counts[items[right].1] == 0 {
            covered += 1;
        }
        counts[items[right].1] += 1;
        v.ptrs(
            &[(disp_r, HighlightKind::Active)],
            &[(disp_r, "R")],
            format!(
                "Add {}(list {}), covered={}/{}",
                items[right].0, items[right].1, covered, k
            ),
        );
        while covered == k {
            let range = items[right].0 - items[left].0;
            if range < best_range.1 - best_range.0 {
                best_range = (items[left].0, items[right].0);
            }
            counts[items[left].1] -= 1;
            if counts[items[left].1] == 0 {
                covered -= 1;
            }
            left += 1;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "L")],
        format!(
            "Answer: smallest range [{}, {}]. O(n log n) — sort + sliding window.",
            best_range.0, best_range.1
        ),
    );
    v.into_frames()
}

fn viz_merge_sort_count_range_sum() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let nums = rand_arr(&mut rng, n, -5, 5);
    let lower = rng.random_range(-5..=0);
    let upper = rng.random_range(1..=10);

    let mut v = VizLog::new(nums.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: count subarrays with sum in [{}, {}]. Strategy: build prefix sums, \
             then check all pairs to count those in range. (Optimal: merge sort on prefix sums.)",
            lower, upper
        ),
    );

    // Build prefix sums
    let mut prefix = vec![0i32; n + 1];
    for i in 0..n {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    let mut count = 0;
    for i in 0..n {
        for j in i..n {
            let s = prefix[j + 1] - prefix[i];
            if s >= lower && s <= upper {
                count += 1;
                v.ptrs(
                    &[(i, HighlightKind::Found), (j, HighlightKind::Found)],
                    &[(i, "L"), (j, "R")],
                    format!(
                        "sum[{}..{}]={} in [{},{}], count={}",
                        i, j, s, lower, upper, count
                    ),
                );
            }
        }
    }
    v.ptrs(
        &[],
        &[],
        format!("Answer: {} subarrays with sum in [{},{}]. O(n^2) brute force, O(n log n) with merge sort.", count, lower, upper),
    );
    v.into_frames()
}

