fn viz_merge_sort_sort_by_frequency() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 6);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        "Goal: sort elements by frequency (most frequent first, ties by value). \
         Strategy: count frequencies with a hash map, then sort with a custom comparator.",
    );

    let mut freq: HashMap<i32, usize> = HashMap::new();
    for &val in &arr {
        *freq.entry(val).or_insert(0) += 1;
    }
    let mut sorted = arr.clone();
    sorted.sort_by(|a, b| {
        let fa = freq[a];
        let fb = freq[b];
        fb.cmp(&fa).then(a.cmp(b))
    });

    for (i, &val) in sorted.iter().enumerate() {
        v.array[i] = val;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "out")],
            format!("Place {}(freq={}) at [{}]", val, freq[&val], i),
        );
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|x| (x, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[],
        format!("Answer: {:?}. O(n log n) — count + sort.", sorted),
    );
    v.into_frames()
}

fn viz_merge_sort_external_sort() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(8..=10);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let chunk_size = 3;
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: sort a large dataset that does not fit in memory. Strategy: divide \
             into chunks of size {}, sort each chunk independently, then merge all sorted chunks.",
            chunk_size
        ),
    );

    // Sort each chunk
    let mut chunks: Vec<Vec<i32>> = Vec::new();
    let mut work = arr.clone();
    let mut i = 0;
    while i < n {
        let end = (i + chunk_size).min(n);
        work[i..end].sort();
        let chunk_hl: Vec<(usize, HighlightKind)> =
            (i..end).map(|x| (x, HighlightKind::Sorted)).collect();
        v.array = work.clone();
        v.ptrs(
            &chunk_hl,
            &[(i, "L"), ((end - 1).min(n - 1), "R")],
            format!("Sort chunk [{},{}]", i, end - 1),
        );
        chunks.push(work[i..end].to_vec());
        i += chunk_size;
    }

    // Merge all chunks (k-way merge simulation)
    let mut result = chunks[0].clone();
    for (ci, chunk) in chunks.iter().enumerate().skip(1) {
        let other = chunk;
        let mut merged = Vec::new();
        let (mut a, mut b) = (0, 0);
        while a < result.len() && b < other.len() {
            if result[a] <= other[b] {
                merged.push(result[a]);
                a += 1;
            } else {
                merged.push(other[b]);
                b += 1;
            }
        }
        while a < result.len() {
            merged.push(result[a]);
            a += 1;
        }
        while b < other.len() {
            merged.push(other[b]);
            b += 1;
        }
        result = merged;
        for (idx, &val) in result.iter().enumerate() {
            if idx < n {
                v.array[idx] = val;
            }
        }
        v.ptrs(
            &[],
            &[(0, "L"), (ci * chunk_size, "R")],
            format!("Merged {} chunks", ci + 1),
        );
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|x| (x, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[],
        "Answer: sorted. O(n log n) total — sort chunks + k-way merge.",
    );
    v.into_frames()
}

