fn viz_matrix_grid_flood_fill() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    let mut grid: Vec<i32> = (0..n).map(|_| rng.random_range(1..=3)).collect();
    let start = rng.random_range(0..n);
    let old_color = grid[start];
    let new_color = old_color + 5;

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: Flood fill from ({},{}) changing color {} to {}. Strategy: DFS/BFS from start, spread to all connected same-color cells. O(rows*cols).",
            start / cols,
            start % cols,
            old_color,
            new_color
        ),
    );

    let mut stack = vec![start];
    let mut visited = vec![false; n];

    while let Some(pos) = stack.pop() {
        if visited[pos] || grid[pos] != old_color {
            continue;
        }
        visited[pos] = true;
        grid[pos] = new_color;
        let r = pos / cols;
        let c = pos % cols;
        v.ptrs(
            &[(pos, HighlightKind::Active)],
            &[(pos, "fill")],
            format!(
                "Fill cell ({},{}) idx={}: change {} to {}. Spread to all 4-connected neighbors with matching color.",
                r, c, pos, old_color, new_color
            ),
        );
        if r > 0 {
            stack.push(pos - cols);
        }
        if r + 1 < rows {
            stack.push(pos + cols);
        }
        if c > 0 {
            stack.push(pos - 1);
        }
        if c + 1 < cols {
            stack.push(pos + 1);
        }
    }

    let filled: Vec<(usize, HighlightKind)> = (0..n)
        .filter(|&i| grid[i] == new_color)
        .map(|i| (i, HighlightKind::Sorted))
        .collect();
    v.ptrs(
        &filled,
        &[(start, "start")],
        format!(
            "Result: {} cells flood-filled. DFS/BFS visits each cell at most once. O(rows*cols).",
            filled.len()
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_island_perimeter() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    let grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=1)).collect();

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Calculate island perimeter in {}x{} grid. Strategy: For each land cell, count edges not shared with another land cell. O(rows*cols).", rows, cols),
    );

    let mut perimeter = 0;
    for i in 0..n {
        if grid[i] == 0 {
            continue;
        }
        let r = i / cols;
        let c = i % cols;
        let mut edges = 4;
        if r > 0 && grid[i - cols] == 1 {
            edges -= 1;
        }
        if r + 1 < rows && grid[i + cols] == 1 {
            edges -= 1;
        }
        if c > 0 && grid[i - 1] == 1 {
            edges -= 1;
        }
        if c + 1 < cols && grid[i + 1] == 1 {
            edges -= 1;
        }
        perimeter += edges;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "cell")],
            format!(
                "Land cell ({},{}) has {} exposed edges (4 minus shared neighbor edges). Running perimeter={}.",
                r, c, edges, perimeter
            ),
        );
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: island perimeter = {}. Each cell contributes 4 minus shared edges. O(rows*cols).", perimeter),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_max_area_island() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    let mut grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=1)).collect();
    grid[0] = 1;

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Find the island with the largest area in {}x{} grid. Strategy: DFS from each unvisited land cell, track max area. O(rows*cols).", rows, cols),
    );

    let mut visited = vec![false; n];
    let mut max_area = 0;

    for start in 0..n {
        if grid[start] == 0 || visited[start] {
            continue;
        }
        let mut stack = vec![start];
        let mut area = 0;
        let mut cells = vec![];
        while let Some(pos) = stack.pop() {
            if visited[pos] || grid[pos] == 0 {
                continue;
            }
            visited[pos] = true;
            area += 1;
            cells.push(pos);
            let r = pos / cols;
            let c = pos % cols;
            v.ptrs(
                &[(pos, HighlightKind::Active)],
                &[(pos, "cell")],
                format!("Visit land cell ({},{}). Current island area={}. DFS expanding to all connected land.", r, c, area),
            );
            if r > 0 {
                stack.push(pos - cols);
            }
            if r + 1 < rows {
                stack.push(pos + cols);
            }
            if c > 0 {
                stack.push(pos - 1);
            }
            if c + 1 < cols {
                stack.push(pos + 1);
            }
        }
        if area > max_area {
            max_area = area;
            let hl: Vec<(usize, HighlightKind)> =
                cells.iter().map(|&i| (i, HighlightKind::Found)).collect();
            v.ptrs(
                &hl,
                &[(cells[0], "best")],
                format!(
                    "New max island area: {}! This island is the largest found so far.",
                    max_area
                ),
            );
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Result: max island area = {}. DFS on each component in O(rows*cols) total.",
            max_area
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_count_islands() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    let mut grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=1)).collect();
    grid[0] = 1;

    let mut v = VizLog::new(grid.clone());
    v.ptrs(&[], &[], format!("Goal: Count distinct islands in {}x{} grid. Strategy: DFS from each unvisited land cell — each new DFS is a new island. O(rows*cols).", rows, cols));

    let mut visited = vec![false; n];
    let mut count = 0;

    for start in 0..n {
        if grid[start] == 0 || visited[start] {
            continue;
        }
        count += 1;
        let mut stack = vec![start];
        while let Some(pos) = stack.pop() {
            if visited[pos] || grid[pos] == 0 {
                continue;
            }
            visited[pos] = true;
            v.ptrs(
                &[(pos, HighlightKind::Active)],
                &[(pos, "visit")],
                format!("Island {}: DFS visits cell {}. Expanding to all connected land cells of this island.", count, pos),
            );
            let r = pos / cols;
            let c = pos % cols;
            if r > 0 {
                stack.push(pos - cols);
            }
            if r + 1 < rows {
                stack.push(pos + cols);
            }
            if c > 0 {
                stack.push(pos - 1);
            }
            if c + 1 < cols {
                stack.push(pos + 1);
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&all, &[(0, "start")], format!("Result: {} islands found. Each DFS from unvisited land starts a new island. O(rows*cols).", count));
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_surrounded_regions() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    let grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=1)).collect();

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Capture surrounded regions in {}x{} grid. Strategy: BFS from border cells — mark safe, capture rest. O(rows*cols).", rows, cols),
    );

    let mut safe = vec![false; n];
    let mut queue = VecDeque::new();
    for i in 0..n {
        let r = i / cols;
        let c = i % cols;
        if (r == 0 || r == rows - 1 || c == 0 || c == cols - 1) && grid[i] == 1 {
            safe[i] = true;
            queue.push_back(i);
        }
    }

    while let Some(pos) = queue.pop_front() {
        v.ptrs(
            &[(pos, HighlightKind::Found)],
            &[(pos, "safe")],
            format!(
                "Cell {} is border-connected — safe from capture. BFS spreads safety to neighbors.",
                pos
            ),
        );
        let r = pos / cols;
        let c = pos % cols;
        for nb in [
            if r > 0 { Some(pos - cols) } else { None },
            if r + 1 < rows { Some(pos + cols) } else { None },
            if c > 0 { Some(pos - 1) } else { None },
            if c + 1 < cols { Some(pos + 1) } else { None },
        ]
        .iter()
        .flatten()
        {
            if grid[*nb] == 1 && !safe[*nb] {
                safe[*nb] = true;
                queue.push_back(*nb);
            }
        }
    }

    let mut captured = 0;
    for i in 0..n {
        if grid[i] == 1 && !safe[i] {
            captured += 1;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Result: {} cells captured (surrounded, not border-connected). O(rows*cols).",
            captured
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_rotting_oranges() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    // 0=empty, 1=fresh, 2=rotten
    let mut grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=2)).collect();
    grid[0] = 2; // at least one rotten

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: Find time for all oranges to rot in {}x{} grid. Strategy: Multi-source BFS from all initially rotten oranges. O(rows*cols).",
            rows, cols
        ),
    );

    let mut queue = VecDeque::new();
    for i in 0..n {
        if grid[i] == 2 {
            queue.push_back((i, 0));
        }
    }

    let mut max_time = 0;
    while let Some((pos, time)) = queue.pop_front() {
        max_time = max_time.max(time);
        let r = pos / cols;
        let c = pos % cols;
        v.ptrs(
            &[(pos, HighlightKind::Swapping)],
            &[(pos, "rot")],
            format!("Minute {}: cell ({},{}) becomes rotten. Rot spreads to adjacent fresh oranges each minute.", time, r, c),
        );
        for nb in [
            if r > 0 { Some(pos - cols) } else { None },
            if r + 1 < rows { Some(pos + cols) } else { None },
            if c > 0 { Some(pos - 1) } else { None },
            if c + 1 < cols { Some(pos + 1) } else { None },
        ]
        .iter()
        .flatten()
        {
            if grid[*nb] == 1 {
                grid[*nb] = 2;
                queue.push_back((*nb, time + 1));
            }
        }
    }

    let fresh_left = grid.iter().filter(|&&x| x == 1).count();
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Result: {} minutes to rot all ({} fresh remaining). Multi-source BFS from rotten oranges. O(rows*cols).",
            if fresh_left > 0 { -1 } else { max_time },
            fresh_left
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_matrix_grid_walls_and_gates() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 5;
    let cols = 5;
    let n = rows * cols;
    // 0=gate, -1=wall, large=empty
    let mut grid: Vec<i32> = (0..n)
        .map(|_| {
            let r = rng.random_range(0..=3);
            if r == 0 {
                0
            } else if r == 1 {
                -1
            } else {
                99
            }
        })
        .collect();
    grid[0] = 0; // at least one gate

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Goal: Fill each empty room with distance to nearest gate in {}x{}. Strategy: Multi-source BFS from all gates simultaneously. O(rows*cols).",
            rows, cols
        ),
    );

    let mut queue = VecDeque::new();
    for i in 0..n {
        if grid[i] == 0 {
            queue.push_back(i);
        }
    }

    while let Some(pos) = queue.pop_front() {
        let r = pos / cols;
        let c = pos % cols;
        v.ptrs(
            &[(pos, HighlightKind::Active)],
            &[(pos, "gate")],
            format!("Process cell ({},{}) at distance {}. BFS from gates propagates shortest distances outward.", r, c, grid[pos]),
        );
        for nb in [
            if r > 0 { Some(pos - cols) } else { None },
            if r + 1 < rows { Some(pos + cols) } else { None },
            if c > 0 { Some(pos - 1) } else { None },
            if c + 1 < cols { Some(pos + 1) } else { None },
        ]
        .iter()
        .flatten()
        {
            if grid[*nb] > grid[pos] + 1 {
                grid[*nb] = grid[pos] + 1;
                queue.push_back(*nb);
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        "Result: all distances to nearest gate computed. Multi-source BFS in O(rows*cols) time."
            .to_string(),
    );
    v.into_grid_frames(rows, cols)
}

