    for (i, &ch) in word.iter().enumerate() {
        v.ptrs(
            &[(i, HighlightKind::Comparing)],
            &[(i, "node")],
            format!("Depth {}: character {} exists in trie. Continue following the path to next character.", i, ch),
        );
    }
    let all: Vec<_> = (0..n).map(|i| (i, HighlightKind::Found)).collect();
