fn viz_fenwick_prefix_sum() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Build a Fenwick tree (BIT) for prefix sum queries and point updates. Strategy: Each index stores a partial sum covering indices determined by the lowest set bit. Query and update in O(log n). Array: {:?}", arr));

    let mut bit = vec![0i32; n + 1];
    for i in 0..n {
        let mut idx = i + 1;
        while idx <= n {
            bit[idx] += arr[i];
            idx += idx & idx.wrapping_neg();
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!("Insert [{}]={} into BIT. Update all responsible BIT nodes using i += i & (-i) traversal.", i, arr[i]),
        );
    }

    // Query prefix sum
    let q = rng.random_range(2..n);
    let mut sum = 0i32;
    let mut idx = q + 1;
    while idx > 0 {
        sum += bit[idx];
        let tree_idx = (idx - 1).min(n - 1);
        v.ptrs(
            &[(tree_idx, HighlightKind::Found)],
            &[(tree_idx, "node")],
            format!(
                "BIT[{}] contributes {}. Running prefix sum={}. Traverse via i -= i & (-i).",
                idx, bit[idx], sum
            ),
        );
        idx -= idx & idx.wrapping_neg();
    }
    let actual: i32 = arr[..=q].iter().sum();
    v.ptrs(
        &[(q, HighlightKind::Found)],
        &[(q, "node")],
        format!(
            "Result: prefix sum [0..{}] = {} (verified={}). Fenwick tree query in O(log n) time.",
            q, sum, actual
        ),
    );
    v.into_frames()
}

fn viz_fenwick_range_update() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 8);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Support range additions and point queries with a Fenwick tree. Strategy: Range update [l,r] += val translates to difference array: add val at l, subtract at r+1. Point query sums the BIT prefix. O(log n).");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let add_val = rng.random_range(1..=5);

    for i in l..=r {
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!("Range update: [{}] value {} increased by {}. BIT difference technique applies to both endpoints.", i, arr[i], add_val),
        );
    }
    let mut updated = arr.clone();
    for i in l..=r {
        updated[i] += add_val;
    }
    v.array = updated.clone();
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Range [{},{}] += {} — {:?}", l, r, add_val, updated),
    );
    v.into_frames()
}

fn viz_fenwick_count_inversions() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Count inversions (pairs where a[i]>a[j] for i<j). Strategy: Scan left-to-right, for each element count how many previous elements are larger using a Fenwick tree for efficient prefix queries.");

    let mut inversions = 0i32;
    for i in 0..n {
        let count_larger = arr[..i].iter().filter(|&&x| x > arr[i]).count() as i32;
        inversions += count_larger;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!(
                "Process [{}]={}: {} earlier elements are larger than {}, so they form inversions. Running total = {}",
                i, arr[i], count_larger, arr[i], inversions
            ),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "node")],
        format!(
            "Answer: {} inversions found. Time: O(n log n) with Fenwick tree.",
            inversions
        ),
    );
    v.into_frames()
}

fn viz_segment_lazy_propagation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Efficiently apply range updates and queries. Strategy: Use lazy propagation to defer updates to children, achieving O(log n) per range operation instead of O(n).");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let add_val = rng.random_range(1..=5);

    // Show lazy update
    v.ptrs(
        &[(l, HighlightKind::Pivot), (r, HighlightKind::Pivot)],
        &[(l, "L"), (r, "R")],
        format!("Range update: add {} to all elements in [{},{}]. Lazy tag stored at internal nodes so we avoid touching every leaf.", add_val, l, r),
    );

    let mut updated = arr.clone();
    for i in l..=r {
        updated[i] += add_val;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!("Push lazy tag down to leaf [{}]: value changes from {} to {} because the pending +{} is now applied.", i, arr[i], updated[i], add_val),
        );
    }
    v.array = updated.clone();
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Answer: range update complete. All values updated: {:?}. Time: O(log n) per range update/query.", updated));
    v.into_frames()
}

fn viz_segment_merge_sort_tree() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Answer order-statistic range queries (e.g., count elements <= k). Strategy: Build a segment tree where each node stores a sorted list of its range, enabling binary search at query time.");

    // Build sorted sublists
    let mid = n / 2;
    let mut left: Vec<i32> = arr[..mid].to_vec();
    left.sort();
    v.ptrs(
        &[(0, HighlightKind::Active), (mid - 1, HighlightKind::Active)],
        &[(0, "L"), (mid - 1, "R")],
        format!("Left child node stores sorted subarray: {:?}. This enables binary search for range queries over the left half.", left),
    );

    let mut right: Vec<i32> = arr[mid..].to_vec();
    right.sort();
    v.ptrs(
        &[(mid, HighlightKind::Active), (n - 1, HighlightKind::Active)],
        &[(mid, "L"), (n - 1, "R")],
        format!("Right child node stores sorted subarray: {:?}. Combined with the left, we can answer queries over any range.", right),
    );

    let mut merged = arr.clone();
    merged.sort();
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Root node stores the fully sorted array: {:?}. Each internal node merges its children.", merged));

    // Query: count <= k in range
    let k = merged[n / 2];
    let l = 0;
    let r = n - 1;
    let count = arr[l..=r].iter().filter(|&&x| x <= k).count();
    v.ptrs(
        &[(l, HighlightKind::Found), (r, HighlightKind::Found)],
        &[(l, "L"), (r, "R")],
        format!("Answer: {} elements <= {} in range [{},{}]. Time: O(log^2 n) per query using binary search at each tree level.", count, k, l, r),
    );
    v.into_frames()
}

fn viz_segment_persistent() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Support point updates while keeping all previous versions queryable. Strategy: On each update, create new nodes only along the root-to-leaf path (path copying), sharing unchanged subtrees with the old version.");

    let mut versions: Vec<Vec<i32>> = vec![arr.clone()];
    for step in 0..3.min(n) {
        let idx = rng.random_range(0..n);
        let new_val = rng.random_range(1..=20);
        let mut new_ver = versions.last().unwrap().clone();
        let old = new_ver[idx];
        new_ver[idx] = new_val;
        versions.push(new_ver.clone());
        v.array = new_ver;
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "node")],
            format!(
                "Version {}: update index [{}] from {} to {}. Only O(log n) new nodes created; old version remains accessible via its root.",
                step + 1,
                idx,
                old,
                new_val
            ),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "node")],
        format!("Answer: {} versions stored, each queryable independently. Time: O(log n) per update, O(n log n) total space.", versions.len()),
    );
    v.into_frames()
}

fn viz_fenwick_2d() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = 9;
    let arr = rand_arr(&mut rng, n, 1, 8);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Support 2D prefix sum queries and point updates. Strategy: Extend the 1D Fenwick tree to two dimensions -- update/query by nesting BIT operations for rows inside BIT operations for columns.");

    let cols = 3;
    let rows = 3;
    // Build row-by-row
    for r in 0..rows {
        let start = r * cols;
        let end = start + cols - 1;
        let row_sum: i32 = arr[start..=end].iter().sum();
        let hl: Vec<_> = (start..=end).map(|i| (i, HighlightKind::Active)).collect();
        v.ptrs(
            &hl,
            &[(start, "L"), (end, "R")],
            format!("Build row {}: sum of this row = {}. Each row maintains its own Fenwick tree for column prefix sums.", r, row_sum),
        );
    }

    // Query submatrix
    let r1 = 0;
    let c1 = 0;
    let r2 = 1;
    let c2 = 1;
    let mut sub_sum = 0;
    for r in r1..=r2 {
        for c in c1..=c2 {
            sub_sum += arr[r * cols + c];
        }
    }
    let hl: Vec<_> = vec![
        (0, HighlightKind::Found),
        (1, HighlightKind::Found),
        (3, HighlightKind::Found),
        (4, HighlightKind::Found),
    ];
    v.ptrs(
        &hl,
        &[(0, "L"), (4, "R")],
        format!("Answer: submatrix sum from ({},{}) to ({},{}) = {}. Time: O(log(r) * log(c)) per query using inclusion-exclusion.", r1, c1, r2, c2, sub_sum),
    );
    v.into_frames()
}

fn viz_segment_interval_scheduling() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.1);
    let arr: Vec<i32> = intervals.iter().map(|x| x.1).collect();
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], "Goal: Find the maximum number of non-overlapping intervals. Strategy: Sort intervals by end time, greedily pick each interval that starts after the previous one ends.");

    let mut end = 0i32;
    let mut count = 0;
    for i in 0..n {
        let (s, e) = intervals[i];
        if s >= end {
            count += 1;
            end = e;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("Accept [{},{}]: starts at {} >= last end {}, so no overlap. Scheduled count = {}.", s, e, s, if count > 1 { end - (e - s) } else { 0 }, count),
            );
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("Reject [{},{}]: starts at {} < current end {}, so it overlaps a scheduled interval.", s, e, s, end),
            );
        }
    }
    v.ptrs(&[], &[], format!("Answer: {} non-overlapping intervals scheduled. Time: O(n log n) for sort + O(n) greedy scan.", count));
    v.into_frames()
}

fn viz_segment_rectangle_union() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let widths = rand_arr(&mut rng, n, 1, 6);
    let heights = rand_arr(&mut rng, n, 1, 6);
    let mut v = VizLog::new(widths.clone());
    v.ptrs(&[], &[], "Goal: Compute the total area covered by the union of rectangles. Strategy: Use coordinate compression and a segment tree to sweep a vertical line across events, tracking active coverage at each x-coordinate.");

    let mut total_area = 0i32;
    for i in 0..n {
        let area = widths[i] * heights[i];
        total_area += area;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!(
                "Rectangle {}: width={}, height={}, individual area={}. Cumulative sum of individual areas = {}.",
                i, widths[i], heights[i], area, total_area
            ),
        );
    }
    // Approximate overlap removal
    let overlap = total_area / 4;
    let union = total_area - overlap;
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "node")],
        format!(
            "Answer: union area ~ {} (sum of areas={}, estimated overlap~{}). Time: O(n log n) with sweep line + segment tree.",
            union, total_area, overlap
        ),
    );
    v.into_frames()
}

fn viz_segment_dynamic() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Handle segment tree operations over a huge value range without pre-allocating all nodes. Strategy: Create tree nodes lazily -- only when an update or query touches a range, allocate nodes for it. Untouched ranges remain null.");

    // Simulate dynamic creation
    let mut created_nodes = 0;
    for i in 0..n {
        created_nodes += 1;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!(
                "Allocate leaf node for index [{}] with value {}. Total nodes so far: {}. Only touched indices get nodes.",
                i, arr[i], created_nodes
            ),
        );
    }
    // Merge phase
    let mut level = n;
    while level > 1 {
        level = level.div_ceil(2);
        created_nodes += level;
        let idx = level.min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "node")],
            format!(
                "Build internal level: {} parent nodes created to aggregate children. Running total: {} nodes allocated.",
                level, created_nodes
            ),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &hl,
        &[],
        format!("Answer: dynamic segment tree uses {} nodes for {} elements (vs {} for a full tree). Time: O(log n) per operation.", created_nodes, n, 4 * n),
    );
    v.into_frames()
}

// ─── Topological Sort ────────────────────────────────────────

fn viz_topo_sort_basic() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = {
        let mut d = vec![0i32; n];
        for u in 0..n {
            for &nb in &adj[u] {
                d[nb] += 1;
            }
        }
        d
    };
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Find a linear ordering of nodes such that for every edge u->v, u comes before v. Strategy: Kahn's algorithm (BFS) -- repeatedly remove nodes with in-degree 0 and add them to the ordering. {} nodes.", n),
    );

    let mut deg = vals.clone();
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && deg[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut order = vec![];
    while let Some(u) = queue.pop_front() {
        order.push(u);
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &[(u, "take")],
            format!("Dequeue node {} because its in-degree is 0 (no unsatisfied dependencies). Add to ordering: {:?}. Decrement in-degrees of its neighbors.", u, order),
        );
        for &nb in &adj[u] {
            deg[nb] -= 1;
            if deg[nb] == 0 {
                queue.push_back(nb);
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Answer: topological order = {:?}. Time: O(V + E).", order),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_can_finish() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = {
        let mut d = vec![0i32; n];
        for u in 0..n {
            for &nb in &adj[u] {
                d[nb] += 1;
            }
        }
        d
    };
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }
    let non_wall = is_wall.iter().filter(|&&w| !w).count();

    let mut v = VizLog::new(vals.clone());
    v.ptrs(&[], &[], format!("Goal: Determine if all courses can be finished (i.e., the prerequisite graph is a DAG). Strategy: Run Kahn's BFS -- if we process all {} non-wall nodes, there is no cycle; otherwise a cycle blocks completion.", non_wall));

    let mut deg = vals.clone();
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && deg[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut count = 0;
    while let Some(u) = queue.pop_front() {
        count += 1;
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &[(u, "take")],
            format!("Process node {}: in-degree was 0, so all prerequisites met. Progress: {}/{} nodes completed.", u, count, non_wall),
        );
        for &nb in &adj[u] {
            deg[nb] -= 1;
            if deg[nb] == 0 {
                queue.push_back(nb);
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Answer: {} ({}/{} nodes processed). Time: O(V + E).",
            if count == non_wall {
                "Can finish -- no cycle detected"
            } else {
                "Cannot finish -- cycle exists, some nodes unreachable"
            },
            count,
            non_wall
        ),
    );
    v.into_grid_frames(rows, cols)
}

