fn viz_topo_sort_is_dag() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);
    let mut vals: Vec<i32> = (0..n as i32).collect();
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Determine if the directed graph is acyclic (a DAG). Strategy: DFS with 3-color marking -- white (unvisited), gray (in progress), black (done). A back edge to a gray node means a cycle exists. {} nodes.", n));

    let mut color = vec![0u8; n]; // 0=white,1=gray,2=black
    let mut is_dag = true;

    for start in 0..n {
        if is_wall[start] || color[start] != 0 {
            continue;
        }
        let mut stack = vec![(start, 0usize)];
        color[start] = 1;
        while let Some((u, idx)) = stack.last_mut() {
            if *idx >= adj[*u].len() {
                let u_val = *u;
                color[u_val] = 2;
                v.ptrs(
                    &[(u_val, HighlightKind::Sorted)],
                    &[(u_val, "done")],
                    format!("Node {} fully explored (all descendants visited). Mark black -- no cycle through this node.", u_val),
                );
                stack.pop();
                continue;
            }
            let nb = adj[*u][*idx];
            let u_val = *u;
            *idx += 1;
            if color[nb] == 1 {
                v.ptrs(
                    &[
                        (u_val, HighlightKind::Swapping),
                        (nb, HighlightKind::Swapping),
                    ],
                    &[(u_val, "node"), (nb, "back")],
                    format!("Back edge {} -> {}: node {} is gray (still being explored), so this edge creates a cycle. Not a DAG!", u_val, nb, nb),
                );
                is_dag = false;
                break;
            } else if color[nb] == 0 {
                color[nb] = 1;
                v.ptrs(
                    &[
                        (u_val, HighlightKind::Active),
                        (nb, HighlightKind::Comparing),
                    ],
                    &[(u_val, "node"), (nb, "visit")],
                    format!(
                        "DFS: explore edge {} -> {}. Mark node {} gray (in progress) and recurse.",
                        u_val, nb, nb
                    ),
                );
                stack.push((nb, 0));
            }
        }
        if !is_dag {
            break;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Answer: {}. Time: O(V + E).",
            if is_dag {
                "Graph IS a DAG (no cycles found)"
            } else {
                "Graph is NOT a DAG (cycle detected)"
            }
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_kahn_bfs() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = {
        let mut d = vec![0i32; n];
        for u in 0..n {
            for &nb in &adj[u] {
                d[nb] += 1;
            }
        }
        d
    };
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals.clone());
    v.ptrs(&[], &[], format!("Goal: Topologically sort {} nodes using BFS (Kahn's algorithm). Strategy: Maintain a queue of nodes with in-degree 0. Dequeue one, reduce neighbors' in-degrees, enqueue any that reach 0.", n));

    let mut deg = vals;
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && deg[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut order = vec![];
    while let Some(u) = queue.pop_front() {
        order.push(u);
        let qfront = queue.front().copied();
        let mut ptrs: Vec<(usize, &str)> = vec![(u, "take")];
        if let Some(f) = qfront {
            ptrs.push((f, "queue"));
        }
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &ptrs,
            format!("Dequeue node {} (in-degree was 0, so safe to place next). {} nodes remain in the ready queue.", u, queue.len()),
        );
        for &nb in &adj[u] {
            deg[nb] -= 1;
            if deg[nb] == 0 {
                queue.push_back(nb);
                v.ptrs(
                    &[(nb, HighlightKind::Comparing)],
                    &[(nb, "ready")],
                    format!("Node {}'s in-degree just dropped to 0 (all predecessors processed). Enqueue it -- it is now ready.", nb),
                );
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Answer: topological order = {:?}. Time: O(V + E).", order),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_parallel_courses() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = {
        let mut d = vec![0i32; n];
        for u in 0..n {
            for &nb in &adj[u] {
                d[nb] += 1;
            }
        }
        d
    };
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Find the minimum number of semesters to finish all courses. Strategy: Level-order BFS (Kahn's) -- each BFS level represents one semester of courses taken in parallel. {} nodes.", n),
    );

    let mut deg = vals;
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && deg[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut semesters = 0;
    let mut taken = 0;
    while !queue.is_empty() {
        semesters += 1;
        let size = queue.len();
        let mut level_nodes = vec![];
        for _ in 0..size {
            let u = queue.pop_front().unwrap();
            taken += 1;
            level_nodes.push(u);
            for &nb in &adj[u] {
                deg[nb] -= 1;
                if deg[nb] == 0 {
                    queue.push_back(nb);
                }
            }
        }
        let hl: Vec<(usize, HighlightKind)> = level_nodes
            .iter()
            .map(|&i| (i, HighlightKind::Sorted))
            .collect();
        v.ptrs(
            &hl,
            &[(level_nodes[0], "sem")],
            format!("Semester {}: take courses {:?} in parallel (all had in-degree 0 at the start of this round).", semesters, level_nodes),
        );
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Answer: {} semesters needed for {} courses. This equals the longest dependency chain. Time: O(V + E).", semesters, taken),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_all_ancestors() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!("Goal: For each node, find all its ancestors in the DAG. Strategy: Process nodes in topological order. When processing node u, propagate u and all of u's ancestors to each neighbor of u. {} nodes.", n),
    );

    let mut ancestors: Vec<HashSet<usize>> = vec![HashSet::new(); n];
    // Process in topo order
    let mut in_deg = vec![0usize; n];
    for u in 0..n {
        for &nb in &adj[u] {
            in_deg[nb] += 1;
        }
    }
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && in_deg[i] == 0 {
            queue.push_back(i);
        }
    }

    while let Some(u) = queue.pop_front() {
        v.ptrs(
            &[(u, HighlightKind::Active)],
            &[(u, "node")],
            format!(
                "Process node {}: its ancestors are {:?}. Now propagate this set (plus {}) to all of node {}'s children.",
                u,
                ancestors[u].iter().collect::<Vec<_>>(),
                u,
                u
            ),
        );
        for &nb in &adj[u] {
            ancestors[nb].insert(u);
            for a in ancestors[u].clone() {
                ancestors[nb].insert(a);
            }
            in_deg[nb] -= 1;
            if in_deg[nb] == 0 {
                queue.push_back(nb);
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Answer: all ancestors computed for {} nodes. Time: O(V^2) in the worst case due to ancestor set sizes.", n),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_longest_path_dag() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Find the longest path in a DAG (critical path). Strategy: Process nodes in topological order, relaxing edges to maximize distance. dist[v] = max(dist[u] + 1) for all predecessors u of v. {} nodes.", n));

    // Topo sort then DP
    let mut in_deg = vec![0usize; n];
    for u in 0..n {
        for &nb in &adj[u] {
            in_deg[nb] += 1;
        }
    }
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && in_deg[i] == 0 {
            queue.push_back(i);
        }
    }
    let mut topo = vec![];
    let mut deg = in_deg;
    while let Some(u) = queue.pop_front() {
        topo.push(u);
        for &nb in &adj[u] {
            deg[nb] -= 1;
            if deg[nb] == 0 {
                queue.push_back(nb);
            }
        }
    }

    let mut dist = vec![0i32; n];
    for &u in &topo {
        for &nb in &adj[u] {
            if dist[nb] < dist[u] + 1 {
                dist[nb] = dist[u] + 1;
            }
        }
        v.ptrs(
            &[(u, HighlightKind::Active)],
            &[(u, "node")],
            format!("Node {}: longest path ending here = {} edges. Now relax outgoing edges to potentially extend paths through this node.", u, dist[u]),
        );
    }

    let best = *dist.iter().max().unwrap_or(&0);
    let best_node = dist.iter().position(|&x| x == best).unwrap_or(0);
    v.ptrs(
        &[(best_node, HighlightKind::Found)],
        &[(best_node, "best")],
        format!(
            "Answer: longest path in DAG = {} edges. Time: O(V + E).",
            best
        ),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_topo_sort_sequence_reconstruction() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.15);

    let mut vals: Vec<i32> = {
        let mut d = vec![0i32; n];
        for u in 0..n {
            for &nb in &adj[u] {
                d[nb] += 1;
            }
        }
        d
    };
    for (i, &wall) in is_wall.iter().enumerate() {
        if wall {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Determine if the topological order is uniquely determined by the given constraints. Strategy: Run Kahn's -- if at any point the queue has more than one element, multiple valid orderings exist (not unique). {} nodes.", n),
    );

    let mut deg = vals;
    let mut queue = VecDeque::new();
    for i in 0..n {
        if !is_wall[i] && deg[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut unique = true;
    let mut order = vec![];
    while let Some(u) = queue.pop_front() {
        if !queue.is_empty() {
            // Check if there was exactly 1 choice
        }
        if queue.is_empty() && order.len() + 1 < n {
            // Could check uniqueness
        }
        order.push(u);
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &[(u, "take")],
            format!("Take node {}. Queue currently has {} other ready nodes. If >0, ordering is ambiguous (multiple valid choices).", u, queue.len()),
        );
        let had_multiple = queue.len();
        for &nb in &adj[u] {
            deg[nb] -= 1;
            if deg[nb] == 0 {
                queue.push_back(nb);
            }
        }
        if had_multiple > 0 {
            unique = false;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Answer: topological order {} unique. Time: O(V + E).",
            if unique { "IS" } else { "is NOT" }
        ),
    );
    v.into_grid_frames(rows, cols)
}

