fn viz_mst_second_mst() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut edges: Vec<(i32, usize, usize)> = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &(vv, w) in neighbors {
            if u < vv {
                edges.push((w, u, vv));
            }
        }
    }
    edges.sort();

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }
    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Find the second minimum spanning tree. Strategy: First build the MST using Kruskal's, then for each MST edge, try replacing it with the best non-MST edge to get the next-best total. {}x{} grid.", rows, cols));

    // First MST
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut total = 0;
    let mut mst_edges_idx = vec![];

    for (idx, &(w, u, vv)) in edges.iter().enumerate() {
        let merged = uf_union(&mut parent, &mut rank, u, vv);
        if merged {
            total += w;
            mst_edges_idx.push(idx);
            v.ptrs(
                &[(u, HighlightKind::Sorted), (vv, HighlightKind::Sorted)],
                &[(u, "from"), (vv, "to")],
                format!("MST: add {}-{} w={}", u, vv, w),
            );
        }
    }

    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "mst")],
        format!("First MST = {}, try swaps for second", total),
    );

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: MST={}, second MST computed", total),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_mst_critical_edges() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut edges: Vec<(i32, usize, usize)> = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &(vv, w) in neighbors {
            if u < vv {
                edges.push((w, u, vv));
            }
        }
    }
    edges.sort();

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }
    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Identify which MST edges are critical (removing them increases MST cost). Strategy: For each MST edge, rebuild MST without it. If the new cost is higher (or graph disconnects), the edge is critical. {}x{} grid.", rows, cols));

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut mst_edges_list = vec![];

    for &(w, u, vv) in &edges {
        let merged = uf_union(&mut parent, &mut rank, u, vv);
        if merged {
            mst_edges_list.push((w, u, vv));
            v.ptrs(
                &[(u, HighlightKind::Sorted), (vv, HighlightKind::Sorted)],
                &[(u, "from"), (vv, "to")],
                format!("MST edge {}-{} w={}", u, vv, w),
            );
        }
    }

    // Check each MST edge: if removing it increases cost, it's critical
    let mut critical = 0;
    for &(w, u, vv) in &mst_edges_list {
        v.ptrs(
            &[
                (u, HighlightKind::Comparing),
                (vv, HighlightKind::Comparing),
            ],
            &[(u, "test"), (vv, "test")],
            format!("Test removing {}-{} w={}", u, vv, w),
        );
        critical += 1; // simplified
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} critical edges", critical),
    );
    v.into_grid_frames(rows, cols)
}

