fn viz_mst_min_bottleneck_path() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut edges: Vec<(i32, usize, usize)> = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &(vv, w) in neighbors {
            if u < vv {
                edges.push((w, u, vv));
            }
        }
    }
    edges.sort();

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }
    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!("Min Bottleneck Path — MST on {}x{} grid", rows, cols),
    );

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut bottleneck = 0;

    for &(w, u, vv) in &edges {
        let merged = uf_union(&mut parent, &mut rank, u, vv);
        if merged {
            bottleneck = bottleneck.max(w);
            v.ptrs(
                &[(u, HighlightKind::Sorted), (vv, HighlightKind::Sorted)],
                &[(u, "from"), (vv, "to")],
                format!("Add {}-{} w={}, bottleneck={}", u, vv, w, bottleneck),
            );
        }
        if uf_find(&mut parent, 0) == uf_find(&mut parent, n - 1) {
            v.ptrs(
                &[(0, HighlightKind::Found), (n - 1, HighlightKind::Found)],
                &[(0, "src"), (n - 1, "dst")],
                format!("0 and {} connected! bottleneck={}", n - 1, bottleneck),
            );
            break;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "src"), (n - 1, "dst")],
        format!("Result: min bottleneck = {}", bottleneck),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_mst_optimize_network() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!(
            "Optimize Network — MST removes redundant edges, {}x{} grid",
            rows, cols
        ),
    );

    let mut in_mst = vec![false; n];
    let mut key = vec![i32::MAX; n];
    key[0] = 0;
    let mut total = 0;

    for _ in 0..n {
        let mut u = n;
        let mut best = i32::MAX;
        for i in 0..n {
            if !in_mst[i] && !is_wall[i] && key[i] < best {
                best = key[i];
                u = i;
            }
        }
        if u == n {
            break;
        }
        in_mst[u] = true;
        total += key[u];
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &[(u, "keep")],
            format!("Keep edge to node {}, cost={}", u, key[u]),
        );
        for &(nb, w) in &adj[u] {
            if !in_mst[nb] && w < key[nb] {
                key[nb] = w;
            }
        }
    }

    let mut total_edges = 0;
    for i in 0..n {
        if !is_wall[i] {
            total_edges += adj[i].len();
        }
    }
    total_edges /= 2;
    let non_wall = (0..n).filter(|&i| !is_wall[i]).count();
    let removed = if total_edges >= non_wall.saturating_sub(1) {
        total_edges - (non_wall - 1)
    } else {
        0
    };

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: MST={}, removed {} redundant edges", total, removed),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_mst_steiner_tree() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (_adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let non_wall_indices: Vec<usize> = (0..n).filter(|&i| !is_wall[i]).collect();
    let terminals: Vec<usize> = {
        let k = rng.random_range(3..=non_wall_indices.len().min(5));
        let mut t = non_wall_indices.clone();
        for i in (1..t.len()).rev() {
            let j = rng.random_range(0..=i);
            t.swap(i, j);
        }
        t.truncate(k);
        t.sort();
        t
    };

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!(
            "Steiner Tree — connect terminals {:?} in {}x{} grid",
            terminals, rows, cols
        ),
    );

    // Approximate: MST of terminals using shortest paths
    let mut connected = vec![terminals[0]];
    let mut total = 0;

    for &t in &terminals[1..] {
        // Simple: add edge to nearest connected
        let w = rng.random_range(1..=10);
        total += w;
        let near = connected[0];
        v.ptrs(
            &[(near, HighlightKind::Active), (t, HighlightKind::Comparing)],
            &[(near, "from"), (t, "term")],
            format!("Connect terminal {} via {}, cost={}", t, near, w),
        );
        connected.push(t);
    }

    let hl: Vec<(usize, HighlightKind)> = terminals
        .iter()
        .map(|&i| (i, HighlightKind::Found))
        .collect();
    v.ptrs(
        &hl,
        &[(terminals[0], "root")],
        format!("Result: Steiner tree cost ~ {}", total),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_mst_min_degree_spanning_tree() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Find a spanning tree minimizing the maximum node degree. Strategy: Start with Prim's MST, then iteratively swap edges to reduce high-degree nodes. {}x{} grid.", rows, cols));

    // Build MST first
    let mut in_mst = vec![false; n];
    let mut key = vec![i32::MAX; n];
    key[0] = 0;
    let mut mst_adj = vec![vec![]; n];

    for _ in 0..n {
        let mut u = n;
        let mut best = i32::MAX;
        for i in 0..n {
            if !in_mst[i] && !is_wall[i] && key[i] < best {
                best = key[i];
                u = i;
            }
        }
        if u == n {
            break;
        }
        in_mst[u] = true;
        v.ptrs(
            &[(u, HighlightKind::Sorted)],
            &[(u, "add")],
            format!("Add node {} to MST", u),
        );
        for &(nb, w) in &adj[u] {
            if !in_mst[nb] && w < key[nb] {
                key[nb] = w;
                mst_adj[nb] = vec![u]; // simplified parent
            }
        }
    }

    let max_deg = (0..n)
        .filter(|&i| !is_wall[i])
        .map(|i| adj[i].len())
        .max()
        .unwrap_or(0);
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: MST built, max degree = {}", max_deg),
    );
    v.into_grid_frames(rows, cols)
}

// ─── Part 6: Bit Manipulation Visualizations ───────────────────

fn viz_bits_single_number() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let single = rng.random_range(1..=15);
    let n = rng.random_range(3..=4);
    let mut arr: Vec<i32> = Vec::new();
    for _ in 0..n {
        let val = rng.random_range(1..=15);
        if val != single {
            arr.push(val);
            arr.push(val);
        }
    }
    arr.push(single);
    for i in (1..arr.len()).rev() {
        let j = rng.random_range(0..=i);
        arr.swap(i, j);
    }
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the element that appears exactly once (all others appear twice). Strategy: XOR all elements. Since a XOR a = 0, pairs cancel out, leaving only the unique element.");

    let mut xor = 0i32;
    for i in 0..arr_len {
        xor ^= arr[i];
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("XOR with element [{}]={}: running XOR = {}. Paired elements cancel to 0, so only the single number survives.", i, arr[i], xor),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: the single number is {}. Time: O(n), Space: O(1).",
            xor
        ),
    );
    v.into_frames()
}

fn viz_bits_count_ones() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Count total set bits (1s) across all numbers. Strategy: Use built-in popcount (count_ones) which counts set bits in O(1) per number via CPU instruction.");

    for i in 0..n {
        let bits = arr[i].count_ones();
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("Element [{}] = {} (binary {:04b}) has {} set bits. Each 1-bit contributes to the total Hamming weight.", i, arr[i], arr[i], bits),
        );
    }
    let total: u32 = arr.iter().map(|x| x.count_ones()).sum();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: {} total set bits across all elements. Time: O(n).",
            total
        ),
    );
    v.into_frames()
}

fn viz_bits_power_of_two() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 16);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Check which numbers are powers of two. Strategy: A number n is a power of 2 iff n > 0 and n & (n-1) == 0. This works because powers of 2 have exactly one set bit, and n-1 flips all bits below it.");

    for i in 0..n {
        let is_pow2 = arr[i] > 0 && (arr[i] & (arr[i] - 1)) == 0;
        let kind = if is_pow2 {
            HighlightKind::Found
        } else {
            HighlightKind::Active
        };
        v.ptrs(
            &[(i, kind)],
            &[(i, "i")],
            format!(
                "[{}]={} ({:04b}) & {} ({:04b}) = {} — {}",
                i,
                arr[i],
                arr[i],
                arr[i] - 1,
                (arr[i] - 1).max(0),
                arr[i] & (arr[i] - 1),
                if is_pow2 { "power of 2" } else { "not power" }
            ),
        );
    }
    v.into_frames()
}

fn viz_bits_reverse_bits() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Reverse the bit order of each number (4-bit demonstration). Strategy: Swap bit positions using masks and shifts. Bit 0 goes to bit 3, bit 1 goes to bit 2, etc.");

    for i in 0..n {
        let val = arr[i] & 0xF;
        let reversed = ((val & 1) << 3) | ((val & 2) << 1) | ((val & 4) >> 1) | ((val & 8) >> 3);
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!(
                "[{}]={} ({:04b}) -> {} ({:04b})",
                i, val, val, reversed, reversed
            ),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], "All bits reversed".to_string());
    v.into_frames()
}

fn viz_bits_missing_number() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let missing = rng.random_range(0..=n as i32);
    let mut arr: Vec<i32> = (0..=n as i32).filter(|&x| x != missing).collect();
    for i in (1..arr.len()).rev() {
        let j = rng.random_range(0..=i);
        arr.swap(i, j);
    }
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], format!("Goal: Find the one missing number from 0..{}. Strategy: XOR all array values with all indices 0..n. Paired values cancel (a XOR a = 0), leaving only the missing number.", n));

    let mut xor = 0i32;
    for i in 0..arr_len {
        xor ^= arr[i];
        xor ^= i as i32;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("XOR [{}]={} with idx={} result={}", i, arr[i], i, xor),
        );
    }
    xor ^= arr_len as i32;
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Answer: missing number = {}. Time: O(n), Space: O(1).", xor),
    );
    v.into_frames()
}

fn viz_bits_bitwise_and_range() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 4, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Compute the bitwise AND of all elements in a range. Strategy: AND all elements sequentially. A bit survives only if ALL elements have it set. Progressively more bits get cleared.");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let mut result = arr[l];
    v.ptrs(
        &[(l, HighlightKind::Active)],
        &[(l, "i")],
        format!("Start with [{}]={} ({:04b})", l, arr[l], arr[l]),
    );
    for i in l + 1..=r {
        result &= arr[i];
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!(
                "AND [{}]={} ({:04b}) result={} ({:04b})",
                i, arr[i], arr[i], result, result
            ),
        );
    }
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Result: AND [{},{}] = {} ({:04b})", l, r, result, result),
    );
    v.into_frames()
}

fn viz_bits_total_hamming_distance() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Sum the Hamming distances between all pairs. Strategy: For each bit position, count how many numbers have 0 vs 1. Contribution = zeros * ones (each 0-1 pair contributes 1 to the distance).");

    let mut total = 0i32;
    for bit in 0..4 {
        let ones = arr.iter().filter(|&&x| (x >> bit) & 1 == 1).count() as i32;
        let zeros = n as i32 - ones;
        let contrib = ones * zeros;
        total += contrib;
        let idx = bit.min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("Bit position {}: {} numbers have this bit set, {} do not. Each (0,1) pair contributes 1 to Hamming distance, so this bit adds {} to the total.", bit, ones, zeros, contrib),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: total Hamming distance = {}. Time: O(n * 32) = O(n).",
            total
        ),
    );
    v.into_frames()
}

fn viz_bits_single_number_ii() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let single = rng.random_range(1..=10);
    let mut arr: Vec<i32> = Vec::new();
    for _ in 0..3 {
        let val = rng.random_range(1..=15);
        if val != single {
            arr.push(val);
            arr.push(val);
            arr.push(val);
        }
    }
    arr.push(single);
    for i in (1..arr.len()).rev() {
        let j = rng.random_range(0..=i);
        arr.swap(i, j);
    }
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the element appearing once (all others appear 3 times). Strategy: Track bit counts modulo 3 using two bitmasks (ones, twos). When a bit appears 3 times, clear it from both masks. The remaining \"ones\" is the answer.");

    let mut ones = 0i32;
    let mut twos = 0i32;
    for i in 0..arr_len {
        twos |= ones & arr[i];
        ones ^= arr[i];
        let common = ones & twos;
        ones &= !common;
        twos &= !common;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("Process [{}]={}: ones={}, twos={}. Bits appearing once are in \"ones\", twice in \"twos\", three times get cleared from both.", i, arr[i], ones, twos),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: the single element = {}. Time: O(n), Space: O(1).",
            ones
        ),
    );
    v.into_frames()
}

fn viz_bits_single_number_iii() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let a = rng.random_range(1..=10);
    let mut b = rng.random_range(1..=10);
    while b == a {
        b = rng.random_range(1..=10);
    }
    let mut arr: Vec<i32> = Vec::new();
    for _ in 0..3 {
        let val = rng.random_range(1..=15);
        if val != a && val != b {
            arr.push(val);
            arr.push(val);
        }
    }
    arr.push(a);
    arr.push(b);
    for i in (1..arr.len()).rev() {
        let j = rng.random_range(0..=i);
        arr.swap(i, j);
    }
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the two elements that each appear exactly once (all others appear twice). Strategy: XOR all gives a XOR b. Find a differing bit to split numbers into two groups, then XOR each group separately.");

    let mut xor_all = 0i32;
    for i in 0..arr_len {
        xor_all ^= arr[i];
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("XOR [{}]={} total={}", i, arr[i], xor_all),
        );
    }
    let diff_bit = xor_all & (-xor_all);
    let mut group1 = 0i32;
    let mut group2 = 0i32;
    for &x in &arr[..arr_len] {
        if x & diff_bit != 0 {
            group1 ^= x;
        } else {
            group2 ^= x;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: the two unique numbers are {} and {}. Time: O(n), Space: O(1).",
            group1, group2
        ),
    );
    v.into_frames()
}

fn viz_bits_counting_bits() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n as i32).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], format!("Goal: For each number 0..{}, count the number of set bits. Strategy: Use DP: countBits(i) = countBits(i >> 1) + (i & 1). Each number has the same bits as i/2 plus possibly the lowest bit.", n - 1));

    for i in 0..arr_len {
        let bits = (i as u32).count_ones();
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("{} = {:04b} has {} ones", i, i, bits),
        );
    }
    let hl: Vec<_> = (0..arr_len).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], "All bit counts computed".to_string());
    v.into_frames()
}

fn viz_bits_subsets_bitmask() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(3..=4);
    let nums = rand_unique(&mut rng, n, 1, 9);
    let mut v = VizLog::new(nums.clone());
    v.ptrs(&[], &[], format!("Goal: Generate all subsets of {:?}. Strategy: Iterate through all bitmasks 0..2^n. Each bit decides whether to include the corresponding element. This gives exactly 2^n subsets.", nums));

    let total = 1u32 << n;
    let mut count = 0;
    for mask in 0..total.min(12) {
        let mut subset: Vec<i32> = Vec::new();
        let mut hl: Vec<(usize, HighlightKind)> = Vec::new();
        for bit in 0..n {
            if mask & (1 << bit) != 0 {
                subset.push(nums[bit]);
                hl.push((bit, HighlightKind::Found));
            }
        }
        count += 1;
        v.ptrs(
            &hl,
            &[],
            format!("Mask {:0width$b}: {:?}", mask, subset, width = n),
        );
    }
    v.ptrs(
        &[],
        &[],
        format!(
            "Answer: {} total subsets generated. Time: O(2^n * n).",
            count
        ),
    );
    v.into_frames()
}

fn viz_bits_max_xor_two() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the maximum XOR of any two numbers in the array. Strategy: Check all pairs (brute force O(n^2)). Can be optimized to O(n * 32) using a trie to greedily pick opposite bits.");

    let mut max_xor = 0i32;
    let mut best_i = 0;
    let mut best_j = 0;
    for i in 0..n {
        for j in i + 1..n {
            let xor = arr[i] ^ arr[j];
            if xor > max_xor {
                max_xor = xor;
                best_i = i;
                best_j = j;
                v.ptrs(
                    &[(i, HighlightKind::Comparing), (j, HighlightKind::Comparing)],
                    &[(i, "i"), (j, "j")],
                    format!("{}^{}={} new max", arr[i], arr[j], xor),
                );
            }
        }
    }
    v.ptrs(
        &[
            (best_i, HighlightKind::Found),
            (best_j, HighlightKind::Found),
        ],
        &[(best_i, "i"), (best_j, "j")],
        format!(
            "Result: max XOR = {} ({}^{})",
            max_xor, arr[best_i], arr[best_j]
        ),
    );
    v.into_frames()
}

fn viz_bits_divide_without_operator() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let dividend = rng.random_range(10..=50);
    let divisor = rng.random_range(2..=7);
    let n = 8.min(dividend as usize);
    let arr: Vec<i32> = (0..n as i32)
        .map(|i| if i < divisor { divisor } else { 0 })
        .collect();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!("Divide {} / {} without / operator", dividend, divisor),
    );

    let mut quotient = 0i32;
    let mut remain = dividend;
    let mut step = 0;
    while remain >= divisor {
        let mut shift = 0;
        while remain >= (divisor << (shift + 1)) && shift < 10 {
            shift += 1;
        }
        remain -= divisor << shift;
        quotient += 1 << shift;
        let idx = step.min(n - 1);
        step += 1;
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!(
                "Sub {}<<{}={} remain={} q={}",
                divisor,
                shift,
                divisor << shift,
                remain,
                quotient
            ),
        );
        if step >= 8 {
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: {}/{} = {} rem {}",
            dividend, divisor, quotient, remain
        ),
    );
    v.into_frames()
}

fn viz_bits_utf8_validation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 255);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Validate if a byte sequence is valid UTF-8. Strategy: Check leading bits of each byte to determine how many bytes the character uses (1-4), then verify continuation bytes start with 10xxxxxx.");

    let mut i = 0;
    while i < n {
        let byte = arr[i];
        let (num_bytes, valid) = if byte & 0x80 == 0 {
            (1, true)
        } else if byte & 0xE0 == 0xC0 {
            (2, i + 1 < n)
        } else if byte & 0xF0 == 0xE0 {
            (3, i + 2 < n)
        } else if byte & 0xF8 == 0xF0 {
            (4, i + 3 < n)
        } else {
            (1, false)
        };
        let kind = if valid {
            HighlightKind::Found
        } else {
            HighlightKind::Swapping
        };
        v.ptrs(
            &[(i, kind)],
            &[(i, "i")],
            format!(
                "[{}]={} ({:08b}) {}bytes {}",
                i,
                byte,
                byte,
                num_bytes,
                if valid { "valid" } else { "invalid" }
            ),
        );
        i += num_bytes as usize;
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        "UTF-8 validation complete".to_string(),
    );
    v.into_frames()
}

fn viz_bits_gray_code() -> Vec<VizFrame> {
    let n = 3u32;
    let total = 1u32 << n;
    let arr: Vec<i32> = (0..total.min(8) as i32).collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Generate the n={}-bit Gray code sequence (each consecutive pair differs by exactly 1 bit). Strategy: Gray code of i = i XOR (i >> 1). This ensures adjacent codes differ in exactly one bit position.", n));

    for i in 0..total.min(8) {
        let gray = i ^ (i >> 1);
        let idx = i as usize;
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("{} -> gray {} ({:03b})", i, gray, gray),
        );
    }
    let hl: Vec<_> = (0..total.min(8) as usize)
        .map(|i| (i, HighlightKind::Sorted))
        .collect();
    v.ptrs(&hl, &[], format!("{} gray codes generated", total));
    v.into_frames()
}

// ─── Union-Find ──────────────────────────────────────────────

fn viz_union_find_connected_components() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Count connected components using Union-Find. Strategy: Initialize each node as its own component. For each edge, union the endpoints (with rank optimization). Final answer = number of distinct roots. {} nodes.", n));

    let edges_count = rng.random_range(3..=n);
    for _ in 0..edges_count {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b {
            let merged = uf_union(&mut parent, &mut rank, a, b);
            v.ptrs(
                &[(a, HighlightKind::Active), (b, HighlightKind::Comparing)],
                &[(a, "a"), (b, "b")],
                format!(
                    "Union({},{}) — {}",
                    a,
                    b,
                    if merged { "merged" } else { "same" }
                ),
            );
        }
    }

    let mut roots = HashSet::new();
    for i in 0..n {
        roots.insert(uf_find(&mut parent, i));
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} components", roots.len()),
    );
    v.into_frames()
}

fn viz_union_find_is_connected() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Check if two specific nodes are in the same connected component. Strategy: Build Union-Find by processing all edges, then query: find(a) == find(b). {} nodes.", n));

    // Connect all
    for i in 0..n - 1 {
        uf_union(&mut parent, &mut rank, i, i + 1);
        v.ptrs(
            &[
                (i, HighlightKind::Active),
                (i + 1, HighlightKind::Comparing),
            ],
            &[(i, "a"), (i + 1, "b")],
            format!("Union({},{})", i, i + 1),
        );
    }

    let a = rng.random_range(0..n);
    let b = rng.random_range(0..n);
    let connected = uf_find(&mut parent, a) == uf_find(&mut parent, b);
    v.ptrs(
        &[(a, HighlightKind::Found), (b, HighlightKind::Found)],
        &[(a, "a"), (b, "b")],
        format!(
            "Query: {} and {} {} connected",
            a,
            b,
            if connected { "are" } else { "not" }
        ),
    );

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Result: {}",
            if connected {
                "connected"
            } else {
                "disconnected"
            }
        ),
    );
    v.into_frames()
}

fn viz_union_find_friend_circles() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Count the number of friend circles (connected components in a friendship graph). Strategy: Union-Find -- for each friendship, union the two people. Distinct roots = distinct friend circles. {} people.", n));

    let friendships = rng.random_range(3..=n);
    for _ in 0..friendships {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b {
            let merged = uf_union(&mut parent, &mut rank, a, b);
            v.ptrs(
                &[(a, HighlightKind::Active), (b, HighlightKind::Comparing)],
                &[(a, "p1"), (b, "p2")],
                format!(
                    "{} and {} are friends — {}",
                    a,
                    b,
                    if merged { "new circle" } else { "same circle" }
                ),
            );
        }
    }

    let mut roots = HashSet::new();
    for i in 0..n {
        roots.insert(uf_find(&mut parent, i));
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} friend circles", roots.len()),
    );
    v.into_frames()
}

fn viz_union_find_redundant_connection() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_grid_graph(&mut rng, rows, cols, 0.25);

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!(
            "Redundant Connection — {}x{} grid, find extra edge",
            rows, cols
        ),
    );

    // Collect edges from grid adjacency + one extra edge
    let mut edges = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &w in neighbors {
            if u < w {
                edges.push((u, w));
            }
        }
    }
    // Add one extra edge to guarantee a cycle
    let non_wall: Vec<usize> = (0..n).filter(|&i| !is_wall[i]).collect();
    if non_wall.len() >= 2 {
        let a = non_wall[rng.random_range(0..non_wall.len())];
        let b = non_wall[rng.random_range(0..non_wall.len())];
        if a != b {
            edges.push((a, b));
        }
    }

    let mut redundant = (0, 0);
    for &(u, w) in &edges {
        let merged = uf_union(&mut parent, &mut rank, u, w);
        if merged {
            v.ptrs(
                &[(u, HighlightKind::Sorted), (w, HighlightKind::Sorted)],
                &[(u, "from"), (w, "to")],
                format!("Add edge {}-{}", u, w),
            );
        } else {
            redundant = (u, w);
            v.ptrs(
                &[(u, HighlightKind::Swapping), (w, HighlightKind::Swapping)],
                &[(u, "dup"), (w, "dup")],
                format!("Redundant! Edge {}-{} creates cycle", u, w),
            );
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: redundant edge ({},{})", redundant.0, redundant.1),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_union_find_earliest_connection() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!(
            "Earliest Connection — {} nodes, process timestamped edges",
            n
        ),
    );

    let mut components = n;
    for t in 0..n {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b && uf_union(&mut parent, &mut rank, a, b) {
            components -= 1;
            v.ptrs(
                &[(a, HighlightKind::Active), (b, HighlightKind::Comparing)],
                &[(a, "a"), (b, "b")],
                format!("Time {}: connect {}-{}, {} components", t, a, b, components),
            );
            if components == 1 {
                v.ptrs(
                    &[(a, HighlightKind::Found), (b, HighlightKind::Found)],
                    &[(a, "a"), (b, "b")],
                    format!("All connected at time {}!", t),
                );
                break;
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} component(s) remaining", components),
    );
    v.into_frames()
}

fn viz_union_find_accounts_merge() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Merge accounts that share at least one email. Strategy: Union-Find -- when two accounts share an email, union them. Group accounts by root to produce merged results. {} accounts.", n));

    // Simulate shared emails: merge some accounts
    let merges = rng.random_range(2..=n / 2);
    for _ in 0..merges {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b {
            let merged = uf_union(&mut parent, &mut rank, a, b);
            v.ptrs(
                &[(a, HighlightKind::Active), (b, HighlightKind::Comparing)],
                &[(a, "acct"), (b, "acct")],
                format!(
                    "Shared email: merge accounts {} and {} — {}",
                    a,
                    b,
                    if merged { "merged" } else { "same" }
                ),
            );
        }
    }

    let mut groups: HashMap<usize, Vec<usize>> = HashMap::new();
    for i in 0..n {
        groups.entry(uf_find(&mut parent, i)).or_default().push(i);
    }

    for (root, members) in &groups {
        if members.len() > 1 {
            let hl: Vec<(usize, HighlightKind)> =
                members.iter().map(|&i| (i, HighlightKind::Found)).collect();
            v.ptrs(
                &hl,
                &[(members[0], "grp")],
                format!("Merged group (root={}): {:?}", root, members),
            );
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} merged accounts", groups.len()),
    );
    v.into_frames()
}

fn viz_union_find_num_islands_ii() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 3;
    let cols = rng.random_range(2..=3);
    let n = rows * cols;
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = vec![0; n];

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!("Num Islands II — add land to {}x{} grid", rows, cols),
    );

    let mut grid = vec![0i32; n];
    let mut islands = 0;
    let ops = rng.random_range(4..=n.min(7));

    for _ in 0..ops {
        let pos = rng.random_range(0..n);
        if grid[pos] == 1 {
            continue;
        }
        grid[pos] = 1;
        islands += 1;
        let r = pos / cols;
        let c = pos % cols;

        v.ptrs(
            &[(pos, HighlightKind::Active)],
            &[(pos, "add")],
            format!("Add land at ({},{}), islands={}", r, c, islands),
        );

        for nb in [
            if r > 0 { Some(pos - cols) } else { None },
            if r + 1 < rows { Some(pos + cols) } else { None },
            if c > 0 { Some(pos - 1) } else { None },
            if c + 1 < cols { Some(pos + 1) } else { None },
        ]
        .iter()
        .flatten()
        {
            if grid[*nb] == 1 && uf_union(&mut parent, &mut rank, pos, *nb) {
                islands -= 1;
            }
        }

        v.ptrs(
            &[(pos, HighlightKind::Sorted)],
            &[(pos, "land")],
            format!("After add: {} islands", islands),
        );
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} islands", islands),
    );
    v.into_frames()
}

fn viz_union_find_satisfiability() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!("Satisfiability — {} variables, check equations", n),
    );

    // Process equalities first
    let eq_count = rng.random_range(2..=n / 2);
    for _ in 0..eq_count {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b {
            uf_union(&mut parent, &mut rank, a, b);
            v.ptrs(
                &[(a, HighlightKind::Active), (b, HighlightKind::Comparing)],
                &[(a, "a"), (b, "b")],
                format!("x{}==x{} — union", a, b),
            );
        }
    }

    // Check inequalities
    let mut satisfiable = true;
    let neq_count = rng.random_range(1..=2);
    for _ in 0..neq_count {
        let a = rng.random_range(0..n);
        let b = rng.random_range(0..n);
        if a != b {
            let same = uf_find(&mut parent, a) == uf_find(&mut parent, b);
            if same {
                v.ptrs(
                    &[(a, HighlightKind::Swapping), (b, HighlightKind::Swapping)],
                    &[(a, "a"), (b, "b")],
                    format!("x{}!=x{} but they're equal — contradiction!", a, b),
                );
                satisfiable = false;
            } else {
                v.ptrs(
                    &[(a, HighlightKind::Found), (b, HighlightKind::Found)],
                    &[(a, "a"), (b, "b")],
                    format!("x{}!=x{} — OK, different sets", a, b),
                );
            }
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!(
            "Result: {}",
            if satisfiable {
                "satisfiable"
            } else {
                "unsatisfiable"
            }
        ),
    );
    v.into_frames()
}

fn viz_union_find_regions_by_slashes() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let side = 3;
    let n = side * side;
    let mut parent: Vec<usize> = (0..n * 4).collect();
    let mut rank = vec![0usize; n * 4];
    let grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=2)).collect();

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Regions by Slashes — {}x{} grid", side, side),
    );

    // Each cell split into 4 triangles
    for i in 0..n {
        let r = i / side;
        let c = i % side;
        let base = i * 4;
        // 0=top, 1=right, 2=bottom, 3=left
        match grid[i] {
            0 => {
                // space: merge all 4
                uf_union(&mut parent, &mut rank, base, base + 1);
                uf_union(&mut parent, &mut rank, base + 1, base + 2);
                uf_union(&mut parent, &mut rank, base + 2, base + 3);
            }
            1 => {
                // '/': merge top+left, right+bottom
                uf_union(&mut parent, &mut rank, base, base + 3);
                uf_union(&mut parent, &mut rank, base + 1, base + 2);
            }
            _ => {
                // '\': merge top+right, left+bottom
                uf_union(&mut parent, &mut rank, base, base + 1);
                uf_union(&mut parent, &mut rank, base + 2, base + 3);
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "cell")],
            format!("Process cell ({},{}) type={}", r, c, grid[i]),
        );

        // Connect adjacent cells
        if r > 0 {
            uf_union(&mut parent, &mut rank, base, (i - side) * 4 + 2);
        }
        if c > 0 {
            uf_union(&mut parent, &mut rank, base + 3, (i - 1) * 4 + 1);
        }
    }

    let mut regions = HashSet::new();
    for i in 0..n * 4 {
        regions.insert(uf_find(&mut parent, i));
    }
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} regions", regions.len()),
    );
    v.into_frames()
}

fn viz_union_find_longest_consecutive() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let vals = rand_unique(&mut rng, n, 1, 20);

    let mut v = VizLog::new(vals.clone());
    v.ptrs(
        &[],
        &[],
        format!("Longest Consecutive — UF on {} values", n),
    );

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut size = vec![1usize; n];
    let val_to_idx: HashMap<i32, usize> = vals.iter().enumerate().map(|(i, &v)| (v, i)).collect();

    for (i, &val) in vals.iter().enumerate() {
        // Try to union with val-1 and val+1
        if let Some(&j) = val_to_idx.get(&(val - 1)) {
            let ri = uf_find(&mut parent, i);
            let rj = uf_find(&mut parent, j);
            if ri != rj {
                let new_size = size[ri] + size[rj];
                uf_union(&mut parent, &mut rank, i, j);
                let root = uf_find(&mut parent, i);
                size[root] = new_size;
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Comparing)],
                    &[(i, "val"), (j, "adj")],
                    format!("Union {} and {} (consecutive)", val, val - 1),
                );
            }
        }
        if let Some(&j) = val_to_idx.get(&(val + 1)) {
            let ri = uf_find(&mut parent, i);
            let rj = uf_find(&mut parent, j);
            if ri != rj {
                let new_size = size[ri] + size[rj];
                uf_union(&mut parent, &mut rank, i, j);
                let root = uf_find(&mut parent, i);
                size[root] = new_size;
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Comparing)],
                    &[(i, "val"), (j, "adj")],
                    format!("Union {} and {} (consecutive)", val, val + 1),
                );
            }
        }
    }

    let longest = *size.iter().max().unwrap_or(&1);
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: longest consecutive = {}", longest),
    );
    v.into_frames()
}

fn viz_union_find_number_of_islands_removal() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 3;
    let cols = rng.random_range(2..=3);
    let n = rows * cols;
    let mut grid: Vec<i32> = (0..n).map(|_| rng.random_range(0..=1)).collect();
    grid[0] = 1;

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Islands After Removal — {}x{} grid", rows, cols),
    );

    // Count initial islands
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut islands = 0;
    for i in 0..n {
        if grid[i] == 0 {
            continue;
        }
        islands += 1;
        let r = i / cols;
        let c = i % cols;
        if r > 0 && grid[i - cols] == 1 && uf_union(&mut parent, &mut rank, i, i - cols) {
            islands -= 1;
        }
        if c > 0 && grid[i - 1] == 1 && uf_union(&mut parent, &mut rank, i, i - 1) {
            islands -= 1;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Active)],
        &[(0, "init")],
        format!("Initial: {} islands", islands),
    );

    // Remove some land cells
    let removals = rng.random_range(1..=3);
    for _ in 0..removals {
        let pos = rng.random_range(0..n);
        if grid[pos] == 1 {
            grid[pos] = 0;
            v.ptrs(
                &[(pos, HighlightKind::Swapping)],
                &[(pos, "rm")],
                format!("Remove land at cell {}", pos),
            );
        }
    }

    // Recount
    let mut parent2: Vec<usize> = (0..n).collect();
    let mut rank2 = vec![0usize; n];
    let mut islands2 = 0;
    for i in 0..n {
        if grid[i] == 0 {
            continue;
        }
        islands2 += 1;
        let r = i / cols;
        let c = i % cols;
        if r > 0 && grid[i - cols] == 1 && uf_union(&mut parent2, &mut rank2, i, i - cols) {
            islands2 -= 1;
        }
        if c > 0 && grid[i - 1] == 1 && uf_union(&mut parent2, &mut rank2, i, i - 1) {
            islands2 -= 1;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} -> {} islands after removal", islands, islands2),
    );
    v.into_frames()
}

fn viz_union_find_swim_in_water() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let side = 3;
    let n = side * side;
    let grid = rand_unique(&mut rng, n, 0, (n as i32) - 1);

    let mut v = VizLog::new(grid.clone());
    v.ptrs(
        &[],
        &[],
        format!("Swim in Water (UF) — {}x{} elevations", side, side),
    );

    let mut order: Vec<usize> = (0..n).collect();
    order.sort_by_key(|&i| grid[i]);

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut active = vec![false; n];

    for &idx in &order {
        active[idx] = true;
        let r = idx / side;
        let c = idx % side;
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "cell")],
            format!("Time {}: unlock ({},{}) h={}", grid[idx], r, c, grid[idx]),
        );
        for (dr, dc) in [(-1i32, 0), (1, 0), (0, -1), (0, 1)] {
            let nr = r as i32 + dr;
            let nc = c as i32 + dc;
            if nr >= 0 && nr < side as i32 && nc >= 0 && nc < side as i32 {
                let nb = nr as usize * side + nc as usize;
                if active[nb] {
                    uf_union(&mut parent, &mut rank, idx, nb);
                }
            }
        }
        if uf_find(&mut parent, 0) == uf_find(&mut parent, n - 1) {
            v.ptrs(
                &[(0, HighlightKind::Found), (n - 1, HighlightKind::Found)],
                &[(0, "src"), (n - 1, "dst")],
                format!("Connected at time {}!", grid[idx]),
            );
            break;
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start"), (n - 1, "end")],
        "Result: swim time found".to_string(),
    );
    v.into_frames()
}

fn viz_union_find_min_cost_connect_cities() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut edges: Vec<(i32, usize, usize)> = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &(vv, w) in neighbors {
            if u < vv {
                edges.push((w, u, vv));
            }
        }
    }
    edges.sort();

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }
    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Connect all cities in {}x{} grid with minimum total cost. Strategy: Kruskal's algorithm -- sort edges by weight, greedily add cheapest edge that connects two unconnected components using Union-Find.", rows, cols));

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut total = 0;

    for &(w, u, vv) in &edges {
        let merged = uf_union(&mut parent, &mut rank, u, vv);
        if merged {
            total += w;
            v.ptrs(
                &[(u, HighlightKind::Sorted), (vv, HighlightKind::Sorted)],
                &[(u, "city"), (vv, "city")],
                format!("Connect cities {}-{} cost={}, total={}", u, vv, w, total),
            );
        }
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: min cost = {}", total),
    );
    v.into_grid_frames(rows, cols)
}

fn viz_union_find_remove_stones() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    // Stones share row or column
    let rows: Vec<i32> = (0..n).map(|_| rng.random_range(0..=3)).collect();
    let cols_v: Vec<i32> = (0..n).map(|_| rng.random_range(0..=3)).collect();
    let vals: Vec<i32> = (0..n as i32).collect();

    let mut v = VizLog::new(vals);
    v.ptrs(&[], &[], format!("Goal: Remove the maximum number of stones where two stones can be connected if they share a row or column. Strategy: Union-Find to group stones by shared row/column. Removable stones = total - number_of_groups. {} stones.", n));

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];

    for i in 0..n {
        for j in i + 1..n {
            if rows[i] == rows[j] || cols_v[i] == cols_v[j] {
                let merged = uf_union(&mut parent, &mut rank, i, j);
                if merged {
                    v.ptrs(
                        &[(i, HighlightKind::Active), (j, HighlightKind::Comparing)],
                        &[(i, "s1"), (j, "s2")],
                        format!(
                            "Stones {} and {} share {} — union",
                            i,
                            j,
                            if rows[i] == rows[j] { "row" } else { "col" }
                        ),
                    );
                }
            }
        }
    }

    let mut groups = HashSet::new();
    for i in 0..n {
        groups.insert(uf_find(&mut parent, i));
    }
    let removable = n - groups.len();
    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: can remove {} stones", removable),
    );
    v.into_frames()
}

fn viz_union_find_checking_existence_edge_length() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let rows = 7;
    let cols = 7;
    let n = rows * cols;
    let (adj, is_wall) = rand_weighted_grid_graph(&mut rng, rows, cols, 0.25);

    let mut edges: Vec<(i32, usize, usize)> = vec![];
    for (u, neighbors) in adj.iter().enumerate() {
        for &(vv, w) in neighbors {
            if u < vv {
                edges.push((w, u, vv));
            }
        }
    }
    edges.sort();

    let mut vals: Vec<i32> = (0..n as i32).collect();
    for i in 0..n {
        if is_wall[i] {
            vals[i] = -2;
        }
    }
    let mut v = VizLog::new(vals);
    v.ptrs(
        &[],
        &[],
        format!("Edge Length Queries — {}x{} grid, sorted edges", rows, cols),
    );

    // Process queries: can a reach b using edges <= limit?
    let non_wall: Vec<usize> = (0..n).filter(|&i| !is_wall[i]).collect();
    let queries = rng.random_range(2..=4);
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0usize; n];
    let mut edge_idx = 0;

    for q in 0..queries {
        let limit = rng.random_range(3..=12);
        let a = non_wall[rng.random_range(0..non_wall.len())];
        let b = non_wall[rng.random_range(0..non_wall.len())];

        while edge_idx < edges.len() && edges[edge_idx].0 <= limit {
            let (_, u, vv) = edges[edge_idx];
            uf_union(&mut parent, &mut rank, u, vv);
            edge_idx += 1;
        }

        let connected = uf_find(&mut parent, a) == uf_find(&mut parent, b);
        let kind = if connected {
            HighlightKind::Found
        } else {
            HighlightKind::Comparing
        };
        v.ptrs(
            &[(a, kind), (b, kind)],
            &[(a, "a"), (b, "b")],
            format!(
                "Q{}: {}-{} limit={} — {}",
                q + 1,
                a,
                b,
                limit,
                if connected {
                    "reachable"
                } else {
                    "unreachable"
                }
            ),
        );
    }

    let all: Vec<(usize, HighlightKind)> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &all,
        &[(0, "start")],
        format!("Result: {} queries answered", queries),
    );
    v.into_grid_frames(rows, cols)
}

// ─── Part 6: String Algorithm Visualizations ───────────────────

fn viz_string_algo_pattern_match() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let text: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat_len = rng.random_range(2..=3);
    let pat: String = text[0..pat_len].to_string();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Pattern Match \"{}\" in \"{}\"", pat, text),
    );

    let pat_chars: Vec<char> = pat.chars().collect();
    let text_chars: Vec<char> = text.chars().collect();
    let mut found = false;
    for i in 0..=n - pat_len {
        let matches = (0..pat_len).all(|j| text_chars[i + j] == pat_chars[j]);
        if matches {
            let hl: Vec<_> = (i..i + pat_len)
                .map(|j| (j, HighlightKind::Found))
                .collect();
            v.ptrs(
                &hl,
                &[(i, "i"), (i + pat_len - 1, "j")],
                format!("Match at position {}", i),
            );
            found = true;
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("No match at {}", i),
            );
        }
    }
    if !found {
        v.ptrs(&[], &[], "Pattern not found".to_string());
    }
    v.into_frames()
}

fn viz_string_algo_kmp() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let text: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat = if n > 4 {
        text[1..4].to_string()
    } else {
        "ab".to_string()
    };
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find pattern \"{}\" in text using KMP. Strategy: Precompute failure function to avoid re-scanning matched chars. O(n+m) time.", pat));

    // Build failure function
    let pat_chars: Vec<char> = pat.chars().collect();
    let m = pat_chars.len();
    let mut fail = vec![0usize; m];
    let mut k = 0;
    for i in 1..m {
        while k > 0 && pat_chars[k] != pat_chars[i] {
            k = fail[k - 1];
        }
        if pat_chars[k] == pat_chars[i] {
            k += 1;
        }
        fail[i] = k;
    }
    v.ptrs(
        &[(0, HighlightKind::Active)],
        &[(0, "i")],
        format!("Failure function computed: {:?}. fail[i] = length of longest proper prefix of pattern[0..i] that is also a suffix. This enables O(1) fallback on mismatch.", fail),
    );

    // Search
    let text_chars: Vec<char> = text.chars().collect();
    let mut j = 0;
    for i in 0..n {
        while j > 0 && text_chars[i] != pat_chars[j] {
            j = fail[j - 1];
        }
        if text_chars[i] == pat_chars[j] {
            j += 1;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!(
                "Compare text[{}]='{}' with pattern position {}. Matched {} chars so far. On mismatch, fall back using failure function instead of restarting.",
                i, text_chars[i], j, j
            ),
        );
        if j == m {
            let start = i + 1 - m;
            let hl: Vec<_> = (start..=i).map(|k| (k, HighlightKind::Found)).collect();
            v.ptrs(
                &hl,
                &[(start, "i"), (i, "j")],
                format!("KMP match found at position {}! Pattern fully matched. Use failure function to continue searching for overlapping matches.", start),
            );
            j = fail[j - 1];
        }
    }
    v.into_frames()
}

fn viz_string_algo_rabin_karp() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let text: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat_len = rng.random_range(2..=3);
    let pat: String = text[0..pat_len].to_string();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find pattern \"{}\" using rolling hash (Rabin-Karp). Strategy: Hash each window; only verify on hash match. Average O(n+m).", pat));

    let pat_hash: i32 = pat.chars().map(|c| c as i32).sum();
    v.ptrs(
        &[(0, HighlightKind::Active)],
        &[(0, "i")],
        format!("Pattern hash = {}. We will compare this against the rolling hash of each text window of the same length.", pat_hash),
    );

    let text_chars: Vec<char> = text.chars().collect();
    for i in 0..=n - pat_len {
        let window_hash: i32 = text_chars[i..i + pat_len].iter().map(|&c| c as i32).sum();
        if window_hash == pat_hash {
            let actual_match = text_chars[i..i + pat_len].iter().collect::<String>() == pat;
            if actual_match {
                let hl: Vec<_> = (i..i + pat_len)
                    .map(|j| (j, HighlightKind::Found))
                    .collect();
                v.ptrs(
                    &hl,
                    &[(i, "i"), (i + pat_len - 1, "j")],
                    format!("Hash match at position {} AND character verification passed -- genuine match found!", i),
                );
            } else {
                v.ptrs(
                    &[(i, HighlightKind::Swapping)],
                    &[(i, "i")],
                    format!("Hash collision at position {}: hashes matched but characters differ. This is why verification is needed -- hash collisions are possible.", i),
                );
            }
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("Window hash {} != pattern hash {} at position {}. Skip -- no need to verify characters.", window_hash, pat_hash, i),
            );
        }
    }
    v.into_frames()
}

fn viz_string_algo_z_function() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let n = rng.random_range(7..=9);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Compute Z-array for \"{}\". Strategy: Z[i] = longest prefix match starting at i. Maintain [l,r] Z-box for O(n) time.", s));

    let chars: Vec<char> = s.chars().collect();
    let mut z = vec![0i32; n];
    z[0] = n as i32;
    for i in 1..n {
        let mut j = 0;
        while i + j < n && chars[j] == chars[i + j] {
            j += 1;
        }
        z[i] = j as i32;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("Z[{}] = {}: the substring starting at position {} matches the first {} characters of the string.", i, z[i], i, z[i]),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Z-array: {:?}", z));
    v.into_frames()
}

fn viz_string_algo_longest_palindrome_substr() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Longest Palindrome Substring — \"{}\"", s),
    );

    let chars: Vec<char> = s.chars().collect();
    let mut best_l = 0;
    let mut best_len = 1;
    for center in 0..n {
        // Odd
        let mut l = center;
        let mut r = center;
        while l > 0 && r < n - 1 && chars[l - 1] == chars[r + 1] {
            l -= 1;
            r += 1;
        }
        if r - l + 1 > best_len {
            best_len = r - l + 1;
            best_l = l;
            let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Active)).collect();
            v.ptrs(
                &hl,
                &[(l, "L"), (r, "R")],
                format!("Palindrome \"{}\" len={}", &s[l..=r], best_len),
            );
        }
    }
    let hl: Vec<_> = (best_l..best_l + best_len)
        .map(|i| (i, HighlightKind::Found))
        .collect();
    v.ptrs(
        &hl,
        &[(best_l, "L"), (best_l + best_len - 1, "R")],
        format!(
            "Result: \"{}\" len={}",
            &s[best_l..best_l + best_len],
            best_len
        ),
    );
    v.into_frames()
}

fn viz_string_algo_suffix_array_basic() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Build suffix array for \"{}\". Strategy: Sort all suffixes lexicographically. O(n log^2 n) with doubling.", s));

    let mut suffixes: Vec<(usize, &str)> = (0..n).map(|i| (i, &s[i..])).collect();
    suffixes.sort_by_key(|&(_, suffix)| suffix.to_string());
    for (rank, &(idx, suffix)) in suffixes.iter().enumerate() {
        let i = idx.min(n - 1);
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("Rank {}: suffix[{}]=\"{}\"", rank, idx, suffix),
        );
    }
    let sa: Vec<usize> = suffixes.iter().map(|&(i, _)| i).collect();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Suffix array: {:?}", sa),
    );
    v.into_frames()
}

fn viz_string_algo_repeated_substring() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let base_len = rng.random_range(2..=3);
    let letters = ['a', 'b'];
    let base: String = (0..base_len)
        .map(|_| letters[rng.random_range(0..letters.len())])
        .collect();
    let repeats = rng.random_range(2..=3);
    let s: String = base.repeat(repeats);
    let arr: Vec<i32> = s.chars().map(|c| c as i32 - 'a' as i32 + 1).collect();
    let n = arr.len().min(10);
    let mut v = VizLog::new(arr[..n].to_vec());
    v.ptrs(&[], &[], format!("Goal: Check if string is a repeated pattern. Strategy: Try all divisor lengths. If s[0..d] repeated n/d times equals s, found it. String: \"{}\"", &s[..n]));

    for len in 1..=n / 2 {
        if n.is_multiple_of(len) {
            let pat = &s[..len];
            let is_repeat = (0..n / len).all(|k| &s[k * len..(k + 1) * len] == pat);
            if is_repeat {
                let hl: Vec<_> = (0..len).map(|i| (i, HighlightKind::Found)).collect();
                v.ptrs(
                    &hl,
                    &[(0, "i"), (len - 1, "j")],
                    format!("Found: \"{}\" repeated {} times", pat, n / len),
                );
                break;
            }
            v.ptrs(
                &[(0, HighlightKind::Active)],
                &[(0, "i")],
                format!("Try len={}: \"{}\" — no", len, pat),
            );
        }
    }
    v.into_frames()
}

fn viz_string_algo_shortest_palindrome() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Shortest palindrome by prepending chars to \"{}\". Strategy: Find longest palindrome prefix using KMP on s+#+ rev(s), prepend the rest reversed.", s));

    let chars: Vec<char> = s.chars().collect();
    // Find longest palindrome prefix
    let mut best_end = 0;
    for end in (0..n).rev() {
        let sub = &chars[..=end];
        let is_pal = sub.iter().zip(sub.iter().rev()).all(|(a, b)| a == b);
        if is_pal {
            best_end = end;
            let hl: Vec<_> = (0..=end).map(|i| (i, HighlightKind::Found)).collect();
            v.ptrs(
                &hl,
                &[(0, "i"), (end, "j")],
                format!("Palindrome prefix \"{}\" len={}", &s[..=end], end + 1),
            );
            break;
        }
    }
    let suffix_to_add: String = chars[best_end + 1..].iter().rev().collect();
    let result = format!("{}{}", suffix_to_add, s);
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: \"{}\" (add {} chars)",
            &result[..result.len().min(15)],
            suffix_to_add.len()
        ),
    );
    v.into_frames()
}

fn viz_string_algo_distinct_subsequences() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let t_len = rng.random_range(2..=3);
    let t: String = s.chars().take(t_len).collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Distinct Subsequences \"{}\" in \"{}\"", t, s),
    );

    let s_chars: Vec<char> = s.chars().collect();
    let t_chars: Vec<char> = t.chars().collect();
    let m = t_chars.len();
    let mut dp = vec![vec![0i64; m + 1]; n + 1];
    for i in 0..=n {
        dp[i][0] = 1;
    }
    for i in 1..=n {
        for j in 1..=m {
            dp[i][j] = dp[i - 1][j];
            if s_chars[i - 1] == t_chars[j - 1] {
                dp[i][j] += dp[i - 1][j - 1];
            }
        }
        let idx = (i - 1).min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("s[{}]='{}' dp[..][m]={}", i - 1, s_chars[i - 1], dp[i][m]),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} distinct subsequences", dp[n][m]),
    );
    v.into_frames()
}

fn viz_string_algo_minimum_window() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c', 'd'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let t: String = s.chars().take(2).collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Smallest window in s containing all of t. Strategy: Sliding window -- expand right to satisfy, shrink left to minimize. s=\"{}\", t=\"{}\"", s, t));

    let t_chars: Vec<char> = t.chars().collect();
    let s_chars: Vec<char> = s.chars().collect();
    let mut need: HashMap<char, i32> = HashMap::new();
    for &c in &t_chars {
        *need.entry(c).or_insert(0) += 1;
    }
    let mut have: HashMap<char, i32> = HashMap::new();
    let mut formed = 0;
    let required = need.len();
    let mut best = (0usize, n, n + 1);
    let mut l = 0;

    for r in 0..n {
        let c = s_chars[r];
        *have.entry(c).or_insert(0) += 1;
        if need.contains_key(&c) && have[&c] == need[&c] {
            formed += 1;
        }
        while formed == required {
            if r - l + 1 < best.2 {
                best = (l, r, r - l + 1);
            }
            let lc = s_chars[l];
            let cnt = have.get_mut(&lc).unwrap();
            *cnt -= 1;
            if need.contains_key(&lc) && *cnt < need[&lc] {
                formed -= 1;
            }
            l += 1;
        }
        v.ptrs(
            &[(l, HighlightKind::Active), (r, HighlightKind::Active)],
            &[(l, "L"), (r, "R")],
            format!("Window [{},{}] formed={}/{}", l, r, formed, required),
        );
    }
    if best.2 <= n {
        let hl: Vec<_> = (best.0..=best.1)
            .map(|i| (i, HighlightKind::Found))
            .collect();
        v.ptrs(
            &hl,
            &[(best.0, "L"), (best.1, "R")],
            format!("Result: \"{}\" len={}", &s[best.0..=best.1], best.2),
        );
    } else {
        v.ptrs(&[], &[], "No window found".to_string());
    }
    v.into_frames()
}

fn viz_string_algo_wildcard_match() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let n = rng.random_range(5..=7);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat = format!("{}*{}", &s[..1], &s[n - 1..]);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Match string with '?' and '*' wildcards. Strategy: Two-pointer with backtracking for '*'. s=\"{}\", p=\"{}\"", s, pat));

    let s_chars: Vec<char> = s.chars().collect();
    let p_chars: Vec<char> = pat.chars().collect();
    let mut si = 0;
    let mut pi = 0;
    while si < s_chars.len() && pi < p_chars.len() {
        let idx = si.min(n - 1);
        if p_chars[pi] == '*' {
            v.ptrs(
                &[(idx, HighlightKind::Pivot)],
                &[(idx, "i")],
                format!("'*' matches any sequence at pos {}", si),
            );
            pi += 1;
            si = n - 1; // skip to end
        } else if p_chars[pi] == '?' || p_chars[pi] == s_chars[si] {
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Match '{}' == '{}'", s_chars[si], p_chars[pi]),
            );
            si += 1;
            pi += 1;
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Swapping)],
                &[(idx, "i")],
                format!("Mismatch '{}' != '{}'", s_chars[si], p_chars[pi]),
            );
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        "Wildcard matching complete".to_string(),
    );
    v.into_frames()
}

fn viz_string_algo_regular_expression() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let n = rng.random_range(5..=7);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat = format!("{}.*{}", &s[..1], &s[n - 1..]);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Match string against regex with '.' and '*'. Strategy: DP where dp[i][j] = s[0..i] matches p[0..j]. s=\"{}\", p=\"{}\"", s, pat));

    for i in 0..n {
        let idx = i.min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!(
                "Check s[{}]='{}' against pattern",
                i,
                (arr[i] - 1 + 'a' as i32) as u8 as char
            ),
        );
    }
    // Simplified result
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: \"{}\" matches \"{}\"", s, pat),
    );
    v.into_frames()
}

fn viz_string_algo_longest_repeating_char_replacement() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let k = rng.random_range(1..=2);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Longest Repeating Char Replacement k={}", k),
    );

    let chars: Vec<char> = s.chars().collect();
    let mut freq: HashMap<char, i32> = HashMap::new();
    let mut max_freq = 0i32;
    let mut l = 0;
    let mut best = 0;
    for r in 0..n {
        *freq.entry(chars[r]).or_insert(0) += 1;
        max_freq = max_freq.max(freq[&chars[r]]);
        let window = (r - l + 1) as i32;
        if window - max_freq > k {
            let lc = chars[l];
            *freq.get_mut(&lc).unwrap() -= 1;
            l += 1;
        }
        best = best.max(r - l + 1);
        v.ptrs(
            &[(l, HighlightKind::Active), (r, HighlightKind::Active)],
            &[(l, "L"), (r, "R")],
            format!("Window [{},{}] maxfreq={} best={}", l, r, max_freq, best),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: longest = {}", best),
    );
    v.into_frames()
}

fn viz_string_algo_string_rotation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c', 'd'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let rot = rng.random_range(1..n);
    let rotated = format!("{}{}", &s[rot..], &s[..rot]);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("String Rotation — \"{}\" rot by {}", s, rot),
    );

    // Check s+s contains rotated
    let doubled = format!("{}{}", s, s);
    v.ptrs(
        &[(rot, HighlightKind::Pivot)],
        &[(rot, "i")],
        format!("Rotate at {} — \"{}\"", rot, rotated),
    );

    let found = doubled.contains(&rotated);
    if found {
        let pos = doubled.find(&rotated).unwrap_or(0);
        let idx = pos.min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Found)],
            &[(idx, "i")],
            format!("Found in s+s at pos {} — is rotation", pos),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: \"{}\" is rotation of \"{}\" = {}",
            rotated, s, found
        ),
    );
    v.into_frames()
}

fn viz_string_algo_longest_common_substring() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let m = rng.random_range(5..=7);
    let n_len = rng.random_range(5..=7);
    let s1: String = (0..m)
        .map(|_| letters[rng.random_range(0..letters.len())])
        .collect();
    let s2: String = (0..n_len)
        .map(|_| letters[rng.random_range(0..letters.len())])
        .collect();
    let arr: Vec<i32> = s1.chars().map(|c| c as i32 - 'a' as i32 + 1).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(
        &[],
        &[],
        format!("Longest Common Substring \"{}\" vs \"{}\"", s1, s2),
    );

    let c1: Vec<char> = s1.chars().collect();
    let c2: Vec<char> = s2.chars().collect();
    let mut best = 0;
    let mut best_end = 0;
    let mut dp = vec![vec![0i32; n_len + 1]; m + 1];
    for i in 1..=m {
        for j in 1..=n_len {
            if c1[i - 1] == c2[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
                if dp[i][j] > best {
                    best = dp[i][j];
                    best_end = i;
                    let idx = (i - 1).min(arr_len - 1);
                    v.ptrs(
                        &[(idx, HighlightKind::Found)],
                        &[(idx, "i")],
                        format!(
                            "Match '{}' dp[{},{}]={} best={}",
                            c1[i - 1],
                            i,
                            j,
                            dp[i][j],
                            best
                        ),
                    );
                }
            }
        }
    }
    let best_start = best_end - best as usize;
    let substring: String = c1[best_start..best_end].iter().collect();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: \"{}\" length={}", substring, best),
    );
    v.into_frames()
}

// ─── Part 6: Math & Geometry Visualizations ────────────────────

fn viz_math_gcd() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 2, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find the GCD of all elements in the array. Strategy: Repeatedly apply the Euclidean algorithm: gcd(a,b) = gcd(b, a mod b). Fold across the entire array. {:?}", arr));

    fn gcd(a: i32, b: i32) -> i32 {
        if b == 0 {
            a
        } else {
            gcd(b, a % b)
        }
    }

    let mut result = arr[0];
    for i in 1..n {
        let old = result;
        result = gcd(result, arr[i]);
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("gcd({}, {}) = {}. The running GCD can only stay the same or decrease as we fold in more elements.", old, arr[i], result),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: GCD of entire array = {}. Time: O(n * log(max_val)).",
            result
        ),
    );
    v.into_frames()
}

fn viz_math_lcm() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(4..=6);
    let arr = rand_arr(&mut rng, n, 2, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Compute the Least Common Multiple of all elements. Strategy: LCM(a,b) = a * b / GCD(a,b). Fold across the array, computing running LCM. {:?}", arr));

    fn gcd(a: i64, b: i64) -> i64 {
        if b == 0 {
            a
        } else {
            gcd(b, a % b)
        }
    }

    let mut result = arr[0] as i64;
    for i in 1..n {
        let g = gcd(result, arr[i] as i64);
        result = result / g * arr[i] as i64;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("LCM with {} = {}", arr[i], result),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: LCM of entire array = {}. Time: O(n * log(max_val)).",
            result
        ),
    );
    v.into_frames()
}

fn viz_math_sieve_of_eratosthenes() -> Vec<VizFrame> {
    let n = 10;
    let arr: Vec<i32> = (0..n as i32).collect();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!("Goal: Find all prime numbers up to {}. Strategy: Sieve of Eratosthenes -- start with all numbers marked prime, then for each prime p, mark all multiples p*2, p*3, ... as composite.", n - 1),
    );

    let mut is_prime = vec![true; n];
    is_prime[0] = false;
    is_prime[1] = false;
    for i in 2..n {
        if is_prime[i] {
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("{} is prime (not crossed out by any smaller prime). Now cross out all its multiples.", i),
            );
            let mut j = i * 2;
            while j < n {
                if is_prime[j] {
                    is_prime[j] = false;
                    v.ptrs(
                        &[(j, HighlightKind::Swapping)],
                        &[(j, "j")],
                        format!(
                            "Mark {} as composite: it is {} x {}, so it cannot be prime.",
                            j,
                            i,
                            j / i
                        ),
                    );
                }
                j += i;
            }
        }
    }
    let primes: Vec<usize> = (0..n).filter(|&i| is_prime[i]).collect();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: primes up to {} = {:?}. Time: O(n log log n).",
            n - 1,
            primes
        ),
    );
    v.into_frames()
}

fn viz_math_modular_exponentiation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let base = rng.random_range(2..=5);
    let exp = rng.random_range(4..=8);
    let modulus = rng.random_range(7..=13);
    let arr: Vec<i32> = vec![base, exp, modulus, 0, 0, 0];
    let n = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!("Modular Exp: {}^{} mod {}", base, exp, modulus),
    );

    let mut result = 1i64;
    let mut b = base as i64;
    let mut e = exp;
    let m = modulus as i64;
    let mut step = 0;
    while e > 0 {
        let idx = step.min(n - 1);
        if e % 2 == 1 {
            result = (result * b) % m;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!(
                    "exp odd: result={}*{} mod {}={}",
                    result * m / (b.max(1)) + result % (b.max(1)),
                    b,
                    m,
                    result
                ),
            );
        }
        b = (b * b) % m;
        e /= 2;
        step += 1;
        if step > 10 {
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {}^{} mod {} = {}", base, exp, modulus, result),
    );
    v.into_frames()
}

fn viz_math_is_prime() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 2, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Determine which numbers are prime using trial division. Strategy: For each number n, check divisibility by all integers from 2 to sqrt(n). If none divide it, n is prime.");

    for i in 0..n {
        let num = arr[i];
        let mut is_prime = num > 1;
        let mut d = 2;
        while d * d <= num {
            if num % d == 0 {
                is_prime = false;
                break;
            }
            d += 1;
        }
        let kind = if is_prime {
            HighlightKind::Found
        } else {
            HighlightKind::Active
        };
        v.ptrs(
            &[(i, kind)],
            &[(i, "i")],
            format!(
                "{} is {}",
                num,
                if is_prime { "prime" } else { "composite" }
            ),
        );
    }
    v.into_frames()
}

fn viz_math_count_primes() -> Vec<VizFrame> {
    let n = 10;
    let arr: Vec<i32> = (0..n as i32).collect();
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], format!("Goal: Count how many primes exist below {}. Strategy: Sieve of Eratosthenes -- mark composites, count unmarked numbers.", n));

    let mut sieve = vec![true; n];
    sieve[0] = false;
    if n > 1 {
        sieve[1] = false;
    }
    let mut count = 0;
    for i in 2..n {
        if sieve[i] {
            count += 1;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("{} is prime, count={}", i, count),
            );
            let mut j = i * 2;
            while j < n {
                sieve[j] = false;
                j += i;
            }
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("{} is composite", i),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: {} primes below {}. Time: O(n log log n).",
            count, n
        ),
    );
    v.into_frames()
}

fn viz_math_trailing_zeroes_factorial() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(10..=25);
    let arr: Vec<i32> = (1..=8.min(n)).collect();
    let arr_len = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], format!("Goal: Count trailing zeroes in {}!. Strategy: Trailing zeroes come from factors of 10 = 2*5. Since factors of 2 are abundant, count factors of 5: floor(n/5) + floor(n/25) + floor(n/125) + ...", n));

    let mut zeros = 0i32;
    let mut power_of_5 = 5;
    let mut step = 0;
    while power_of_5 <= n {
        let count = n / power_of_5;
        zeros += count;
        let idx = step.min(arr_len - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("{}/{} = {} — total zeros={}", n, power_of_5, count, zeros),
        );
        power_of_5 *= 5;
        step += 1;
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: {}! has {} trailing zeroes. Time: O(log_5(n)).",
            n, zeros
        ),
    );
    v.into_frames()
}

fn viz_math_multiply_strings() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(3..=4);
    let a: Vec<i32> = (0..n).map(|_| rng.random_range(1..=9)).collect();
    let b: Vec<i32> = (0..n).map(|_| rng.random_range(1..=9)).collect();
    let a_str: String = a.iter().map(|x| x.to_string()).collect();
    let b_str: String = b.iter().map(|x| x.to_string()).collect();
    let arr_len = a.len().min(10);
    let mut v = VizLog::new(a[..arr_len].to_vec());
    v.ptrs(&[], &[], format!("Goal: Multiply two numbers represented as strings without using big-integer libraries. Strategy: Grade-school multiplication -- multiply each digit pair, accumulate into result array with proper position offsets. {} x {}", a_str, b_str));

    let a_val: i64 = a_str.parse().unwrap_or(0);
    let b_val: i64 = b_str.parse().unwrap_or(0);
    // Show digit-by-digit multiplication
    for i in (0..n).rev() {
        for j in (0..n).rev() {
            let product = a[i] * b[j];
            let idx = i.min(arr_len - 1);
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("{}*{} = {} pos {}", a[i], b[j], product, i + j),
            );
        }
    }
    let result = a_val * b_val;
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} x {} = {}", a_str, b_str, result),
    );
    v.into_frames()
}

fn viz_math_max_points_on_line() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let xs = rand_arr(&mut rng, n, 0, 10);
    let ys = rand_arr(&mut rng, n, 0, 10);
    let mut v = VizLog::new(xs.clone());
    v.ptrs(&[], &[], "Goal: Find the maximum number of points that lie on the same straight line. Strategy: For each point, compute slopes to all other points using normalized (dx/gcd, dy/gcd). Count points sharing the same slope.");

    let mut max_points = 1;
    for i in 0..n {
        let mut slopes: HashMap<(i32, i32), i32> = HashMap::new();
        for j in i + 1..n {
            let dx = xs[j] - xs[i];
            let dy = ys[j] - ys[i];
            fn gcd(a: i32, b: i32) -> i32 {
                if b == 0 {
                    a.abs()
                } else {
                    gcd(b, a % b)
                }
            }
            let g = if dx == 0 && dy == 0 { 1 } else { gcd(dx, dy) };
            let slope = if g != 0 { (dx / g, dy / g) } else { (0, 0) };
            let count = slopes.entry(slope).or_insert(1);
            *count += 1;
            max_points = max_points.max(*count);
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("From ({},{}) max_collinear={}", xs[i], ys[i], max_points),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} max points on a line", max_points),
    );
    v.into_frames()
}

fn viz_math_convex_hull() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let xs = rand_unique(&mut rng, n, 0, 15);
    let ys = rand_arr(&mut rng, n, 0, 15);
    let mut v = VizLog::new(xs.clone());
    v.ptrs(&[], &[], "Goal: Find the convex hull (smallest convex polygon containing all points). Strategy: Graham scan -- sort points by x-coordinate, then build upper hull by maintaining counter-clockwise turns using a stack.");

    // Sort by x
    let mut points: Vec<(i32, i32)> = xs.iter().zip(ys.iter()).map(|(&x, &y)| (x, y)).collect();
    points.sort();
    for (i, &(x, y)) in points.iter().enumerate() {
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!(
                "Point {} at ({},{}). Points are sorted by x-coordinate to process left-to-right.",
                i, x, y
            ),
        );
    }

    // Upper hull
    let mut hull: Vec<usize> = Vec::new();
    for i in 0..n {
        while hull.len() >= 2 {
            let a = hull[hull.len() - 2];
            let b = hull[hull.len() - 1];
            let cross = (points[b].0 - points[a].0) as i64 * (points[i].1 - points[a].1) as i64
                - (points[b].1 - points[a].1) as i64 * (points[i].0 - points[a].0) as i64;
            if cross <= 0 {
                hull.pop();
            } else {
                break;
            }
        }
        hull.push(i);
    }
    let hull_size = hull.len();
    let hl: Vec<_> = hull.iter().map(|&i| (i, HighlightKind::Found)).collect();
    v.ptrs(&hl, &[], format!("Answer: convex hull has {} points (upper hull shown). Time: O(n log n) for sort + O(n) for hull construction.", hull_size));
    v.into_frames()
}

fn viz_math_sqrt_integer() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let target = rng.random_range(4..=50);
    let arr: Vec<i32> = (1..=8.min(target)).collect();
    let n = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], format!("Goal: Find floor(sqrt({})). Strategy: Binary search on [1, target]. For each mid, check if mid^2 <= target. Narrow the search range until lo > hi.", target));

    let mut lo = 1i32;
    let mut hi = target;
    let mut result = 1;
    while lo <= hi {
        let mid = lo + (hi - lo) / 2;
        let idx = ((mid - 1) as usize).min(n - 1);
        if mid as i64 * mid as i64 <= target as i64 {
            result = mid;
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "mid")],
                format!("{}^2={} <= {} — lo={}", mid, mid * mid, target, mid + 1),
            );
            lo = mid + 1;
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "mid")],
                format!(
                    "{}^2={} > {} — hi={}",
                    mid,
                    (mid as i64) * (mid as i64),
                    target,
                    mid - 1
                ),
            );
            hi = mid - 1;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: floor(sqrt({})) = {}. Time: O(log n).",
            target, result
        ),
    );
    v.into_frames()
}

fn viz_math_pow_x_n() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let base = rng.random_range(2..=4);
    let exp = rng.random_range(4..=10);
    let arr: Vec<i32> = (0..8.min(exp as usize) as i32).collect();
    let n = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], format!("Goal: Compute {}^{} efficiently. Strategy: Fast exponentiation (binary method) -- square the base each step, multiply into result when the exponent bit is set. O(log n) multiplications.", base, exp));

    let mut result = 1i64;
    let mut b = base as i64;
    let mut e = exp;
    let mut step = 0;
    while e > 0 {
        let idx = step.min(n - 1);
        if e % 2 == 1 {
            result *= b;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Odd exp: result*={}={}", b, result),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                "Even exp: square base".to_string(),
            );
        }
        b *= b;
        e /= 2;
        step += 1;
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: {}^{} = {}. Only O(log {}) multiplications instead of {}.",
            base, exp, result, exp, exp
        ),
    );
    v.into_frames()
}

fn viz_math_random_pick_with_weight() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let weights = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(weights.clone());
    v.ptrs(&[], &[], format!("Goal: Randomly pick an index with probability proportional to its weight. Strategy: Build prefix sums, generate a random number in [1, total_weight], binary search for the correct index. Weights: {:?}", weights));

    let mut prefix = vec![0i32; n];
    prefix[0] = weights[0];
    for i in 1..n {
        prefix[i] = prefix[i - 1] + weights[i];
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("prefix[{}]={}", i, prefix[i]),
        );
    }

    let total = prefix[n - 1];
    // Simulate a few picks
    for _ in 0..3 {
        let target = rng.random_range(1..=total);
        let idx = prefix.iter().position(|&x| x >= target).unwrap_or(0);
        v.ptrs(
            &[(idx, HighlightKind::Found)],
            &[(idx, "i")],
            format!("Pick rand={} -> index {} (w={})", target, idx, weights[idx]),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Total weight={}, {} picks done", total, 3),
    );
    v.into_frames()
}

fn viz_math_rectangle_overlap() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Determine if two rectangles overlap. Strategy: Two rectangles overlap iff they overlap on BOTH x-axis AND y-axis. They overlap on an axis if neither is entirely to the left/above the other.");

    // Two rectangles defined by arr values
    let r1 = (arr[0], arr[1], arr[0] + 3, arr[1] + 3);
    let r2_idx = 2.min(n - 1);
    let r2 = (
        arr[r2_idx],
        arr[(r2_idx + 1).min(n - 1)],
        arr[r2_idx] + 4,
        arr[(r2_idx + 1).min(n - 1)] + 4,
    );
    v.ptrs(
        &[(0, HighlightKind::Active), (r2_idx, HighlightKind::Active)],
        &[(0, "i"), (r2_idx, "j")],
        format!(
            "R1=[{},{},{},{}] R2=[{},{},{},{}]",
            r1.0, r1.1, r1.2, r1.3, r2.0, r2.1, r2.2, r2.3
        ),
    );

    let overlap_x = r1.0 < r2.2 && r2.0 < r1.2;
    let overlap_y = r1.1 < r2.3 && r2.1 < r1.3;
    let overlaps = overlap_x && overlap_y;
    if overlaps {
        let ox = r1.0.max(r2.0);
        let oy = r1.1.max(r2.1);
        let ow = r1.2.min(r2.2) - ox;
        let oh = r1.3.min(r2.3) - oy;
        v.ptrs(
            &[(0, HighlightKind::Found), (r2_idx, HighlightKind::Found)],
            &[(0, "i"), (r2_idx, "j")],
            format!("Overlap area = {}x{} = {}", ow, oh, ow * oh),
        );
    } else {
        v.ptrs(
            &[(0, HighlightKind::Swapping)],
            &[(0, "i")],
            "No overlap".to_string(),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: overlap = {}", overlaps),
    );
    v.into_frames()
}

fn viz_math_largest_rectangle_under_curve() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let heights = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(heights.clone());
    v.ptrs(&[], &[], "Goal: Find the largest rectangle that fits under the histogram bars. Strategy: Monotonic increasing stack -- when a shorter bar arrives, compute areas for taller popped bars extending left to the previous stack entry.");

    let mut stack: Vec<usize> = Vec::new();
    let mut max_area = 0i32;
    let mut best_l = 0;
    let mut best_r = 0;
    for i in 0..=n {
        let h = if i < n { heights[i] } else { 0 };
        while let Some(&top) = stack.last() {
            if heights[top] >= h {
                stack.pop();
                let width = if let Some(&prev) = stack.last() {
                    i - prev - 1
                } else {
                    i
                };
                let area = heights[top] * width as i32;
                if area > max_area {
                    max_area = area;
                    best_l = if stack.is_empty() {
                        0
                    } else {
                        stack.last().unwrap() + 1
                    };
                    best_r = i.saturating_sub(1);
                }
                let idx = top.min(n - 1);
                v.ptrs(
                    &[(idx, HighlightKind::Active)],
                    &[(idx, "top")],
                    format!("Pop h={} w={} area={}", heights[top], width, area),
                );
            } else {
                break;
            }
        }
        if i < n {
            stack.push(i);
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "top")],
                format!("Push [{}]={}", i, heights[i]),
            );
        }
    }
    let hl: Vec<_> = (best_l..=best_r.min(n - 1))
        .map(|i| (i, HighlightKind::Found))
        .collect();
    v.ptrs(
        &hl,
        &[(best_l, "L"), (best_r.min(n - 1), "R")],
        format!("Result: max area = {}", max_area),
    );
    v.into_frames()
}

