// ─── Backtracking ────────────────────────────────────────────

fn viz_backtracking_binary_strings() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(3..=4);
    let arr: Vec<i32> = vec![0; n];
    let mut v = VizLog::new(arr);
    v.ptrs(&[], &[], format!("Goal: Generate all binary strings of length {}. Strategy: Backtracking -- at each position, try 0 and 1. Recurse to fill the next position, then backtrack to try the other choice. 2^n total strings.", n));

    let mut results: Vec<Vec<i32>> = Vec::new();
    let mut current: Vec<i32> = Vec::new();

    fn gen(n: usize, cur: &mut Vec<i32>, res: &mut Vec<Vec<i32>>, v: &mut VizLog) {
        if cur.len() == n {
            res.push(cur.clone());
            let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Found)).collect();
            v.ptrs(&hl, &[], format!("#{}: {:?}", res.len(), cur));
            return;
        }
        if res.len() >= 10 {
            return;
        }
        for bit in 0..=1 {
            cur.push(bit);
            let idx = cur.len() - 1;
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "pick")],
                format!("Pick {} — current={:?}", bit, cur),
            );
            gen(n, cur, res, v);
            cur.pop();
            if res.len() < 10 {
                v.ptrs(
                    &[(idx, HighlightKind::Swapping)],
                    &[(idx, "pick")],
                    format!("Backtrack: undo {}", bit),
                );
            }
        }
    }

    gen(n, &mut current, &mut results, &mut v);
    v.ptrs(
        &[],
        &[],
        format!("Result: {} binary strings", results.len()),
    );
    v.into_frames()
}

fn viz_backtracking_combination_sum_ii() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let cand_len = rng.random_range(5..=7);
    let mut candidates = rand_arr(&mut rng, cand_len, 1, 6);
    candidates.sort();
    let target = rng.random_range(6..=10);
    let n = candidates.len().min(8);
    let mut v = VizLog::new(candidates[..n].to_vec());
    v.ptrs(
        &[],
        &[],
        format!(
            "Combination Sum II — target={}, {:?}",
            target,
            &candidates[..n]
        ),
    );

    let mut results: Vec<Vec<i32>> = Vec::new();
    let mut current: Vec<i32> = Vec::new();

    fn gen(
        cands: &[i32],
        idx: usize,
        target: i32,
        cur: &mut Vec<i32>,
        res: &mut Vec<Vec<i32>>,
        v: &mut VizLog,
        n: usize,
    ) {
        if target == 0 {
            res.push(cur.clone());
            let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Found)).collect();
            v.ptrs(&hl, &[], format!("Found: {:?}", cur));
            return;
        }
        if target < 0 || res.len() >= 6 {
            return;
        }
        for i in idx..cands.len() {
            if i > idx && cands[i] == cands[i - 1] {
                continue;
            }
            if cands[i] > target {
                break;
            }
            cur.push(cands[i]);
            let vi = i.min(n - 1);
            v.ptrs(
                &[(vi, HighlightKind::Active)],
                &[(vi, "pick")],
                format!("Pick {} remain={}", cands[i], target - cands[i]),
            );
            gen(cands, i + 1, target - cands[i], cur, res, v, n);
            cur.pop();
            if res.len() < 6 {
                v.ptrs(
                    &[(vi, HighlightKind::Swapping)],
                    &[(vi, "pick")],
                    format!("Backtrack: undo {}", cands[i]),
                );
            }
        }
    }

    gen(
        &candidates,
        0,
        target,
        &mut current,
        &mut results,
        &mut v,
        n,
    );
    v.ptrs(
        &[],
        &[],
        format!("Result: {} combinations found", results.len()),
    );
    v.into_frames()
}

// ─── Greedy ──────────────────────────────────────────────────

fn viz_greedy_lemonade_change() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let choices = [5, 5, 5, 10, 10, 20];
    let bills: Vec<i32> = (0..n)
        .map(|i| {
            if i < 2 {
                5
            } else {
                choices[rng.random_range(0..choices.len())]
            }
        })
        .collect();
    let mut v = VizLog::new(bills.clone());
    v.ptrs(&[], &[], format!("Goal: Determine if we can make correct change for every customer. Strategy: Greedy -- track counts of $5 and $10 bills. For $10 give back $5. For $20, prefer $10+$5 (saves $5 bills) over 3x$5. Bills: {:?}", bills));

    let mut fives = 0i32;
    let mut tens = 0i32;
    let mut ok = true;
    for i in 0..n {
        let bill = bills[i];
        if bill == 5 {
            fives += 1;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("$5 — no change (5s={} 10s={})", fives, tens),
            );
        } else if bill == 10 {
            if fives > 0 {
                fives -= 1;
                tens += 1;
                v.ptrs(
                    &[(i, HighlightKind::Active)],
                    &[(i, "i")],
                    format!("$10 — give $5 (5s={} 10s={})", fives, tens),
                );
            } else {
                ok = false;
                v.ptrs(
                    &[(i, HighlightKind::Swapping)],
                    &[(i, "i")],
                    "Cannot make change for $10".to_string(),
                );
                break;
            }
        } else if tens > 0 && fives > 0 {
            tens -= 1;
            fives -= 1;
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("$20 — give $10+$5 (5s={} 10s={})", fives, tens),
            );
        } else if fives >= 3 {
            fives -= 3;
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("$20 — give 3x$5 (5s={} 10s={})", fives, tens),
            );
        } else {
            ok = false;
            v.ptrs(
                &[(i, HighlightKind::Swapping)],
                &[(i, "i")],
                "Cannot make change for $20".to_string(),
            );
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {}", if ok { "success" } else { "failed" }),
    );
    v.into_frames()
}

fn viz_greedy_maximum_units() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let units = rand_arr(&mut rng, n, 1, 10);
    let mut indexed: Vec<(i32, usize)> = units.iter().copied().zip(0..n).collect();
    indexed.sort_by(|a, b| b.0.cmp(&a.0));
    let truck_size = rng.random_range(3..=5);
    let mut v = VizLog::new(units.clone());
    v.ptrs(
        &[],
        &[],
        format!("Maximum Units — truck fits {} boxes", truck_size),
    );

    let mut total = 0i32;
    let mut remaining = truck_size;
    for &(u, idx) in &indexed {
        if remaining <= 0 {
            break;
        }
        total += u;
        remaining -= 1;
        let vi = idx.min(n - 1);
        v.ptrs(
            &[(vi, HighlightKind::Found)],
            &[(vi, "pick")],
            format!("Take box {} units={} total={}", idx, u, total),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} total units", total),
    );
    v.into_frames()
}

fn viz_greedy_can_place_flowers() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let mut bed: Vec<i32> = (0..n)
        .map(|_| if rng.random_range(0..3) == 0 { 1 } else { 0 })
        .collect();
    for i in 1..n {
        if bed[i] == 1 && bed[i - 1] == 1 {
            bed[i] = 0;
        }
    }
    let mut v = VizLog::new(bed.clone());
    v.ptrs(&[], &[], format!("Goal: Count how many flowers can be planted without adjacent flowers. Strategy: Greedy left-to-right scan. Plant at position i if arr[i]==0 and both neighbors are 0 (or don't exist). Bed: {:?}", bed));

    let mut count = 0;
    let mut arr = bed.clone();
    for i in 0..n {
        let left_ok = i == 0 || arr[i - 1] == 0;
        let right_ok = i == n - 1 || arr[i + 1] == 0;
        if arr[i] == 0 && left_ok && right_ok {
            arr[i] = 1;
            count += 1;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("Plant at {} (count={})", i, count),
            );
        } else {
            let kind = if arr[i] == 1 {
                HighlightKind::Sorted
            } else {
                HighlightKind::Active
            };
            v.ptrs(
                &[(i, kind)],
                &[(i, "i")],
                format!("[{}]={} skip", i, bed[i]),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: can place {} flowers", count),
    );
    v.into_frames()
}

fn viz_greedy_min_number_arrows() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.1);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the minimum number of arrows to burst all balloons. Strategy: Sort balloons by end point. Greedily shoot at the end of the first un-burst balloon -- this pops all overlapping balloons.");

    let mut arrows = 0;
    let mut arrow_pos = i32::MIN;
    for i in 0..n {
        let (s, e) = intervals[i];
        let idx = (2 * i).min(arr_len - 1);
        if s > arrow_pos {
            arrows += 1;
            arrow_pos = e;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Arrow {} at {} for [{},{}]", arrows, e, s, e),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("[{},{}] burst by arrow at {}", s, e, arrow_pos),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} arrows", arrows),
    );
    v.into_frames()
}

// ─── Dynamic Programming ─────────────────────────────────────

fn viz_dp_min_cost_stairs() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let cost = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(cost.clone());
    v.ptrs(&[], &[], format!("Goal: Reach the top of the staircase with minimum cost. Strategy: DP where dp[i] = min cost to reach step i. At each step, choose the cheaper of (step from i-1) or (step from i-2). Costs: {:?}", cost));

    let mut dp = cost.clone();
    for i in 2..n {
        dp[i] = cost[i] + dp[i - 1].min(dp[i - 2]);
        v.array = dp.clone();
        v.ptrs(
            &[
                (i, HighlightKind::Active),
                (i - 1, HighlightKind::Comparing),
                (i - 2, HighlightKind::Comparing),
            ],
            &[(i, "i")],
            format!(
                "dp[{}] = {} + min({},{}) = {}",
                i,
                cost[i],
                dp[i - 1],
                dp[i - 2],
                dp[i]
            ),
        );
    }
    let result = dp[n - 1].min(dp[n - 2]);
    v.ptrs(
        &[(n - 1, HighlightKind::Found)],
        &[(n - 1, "i")],
        format!("Answer: minimum cost to reach the top = {}. Time: O(n), Space: O(1) with optimization.", result),
    );
    v.into_frames()
}

fn viz_dp_fibonacci() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let mut dp = vec![0i32; n];
    dp[0] = 0;
    if n > 1 {
        dp[1] = 1;
    }
    let mut v = VizLog::new(dp.clone());
    v.ptrs(&[], &[], format!("Goal: Compute the first {} Fibonacci numbers using DP. Strategy: Bottom-up tabulation. dp[0]=0, dp[1]=1, dp[i] = dp[i-1] + dp[i-2]. Each number is the sum of the two preceding ones.", n));
    v.ptrs(
        &[(0, HighlightKind::Sorted)],
        &[(0, "i")],
        "dp[0]=0".to_string(),
    );
    if n > 1 {
        v.ptrs(
            &[(1, HighlightKind::Sorted)],
            &[(1, "i")],
            "dp[1]=1".to_string(),
        );
    }
    for i in 2..n {
        dp[i] = dp[i - 1] + dp[i - 2];
        v.array = dp.clone();
        v.ptrs(
            &[
                (i, HighlightKind::Active),
                (i - 1, HighlightKind::Comparing),
                (i - 2, HighlightKind::Comparing),
            ],
            &[(i, "i")],
            format!(
                "dp[{}] = dp[{}]+dp[{}] = {}+{} = {}",
                i,
                i - 1,
                i - 2,
                dp[i - 1],
                dp[i - 2],
                dp[i]
            ),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &hl,
        &[],
        format!(
            "Answer: fib({}) = {}. Time: O(n), Space: O(n) or O(1) with rolling variables.",
            n - 1,
            dp[n - 1]
        ),
    );
    v.into_frames()
}

fn viz_dp_max_subarray() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let nums = rand_arr(&mut rng, n, -5, 10);
    let mut v = VizLog::new(nums.clone());
    v.ptrs(&[], &[], format!("Goal: Find the contiguous subarray with the largest sum. Strategy: Kadane's algorithm -- maintain a running sum; if it drops below the current element, restart from here. Track the global maximum. Array: {:?}", nums));

    let mut max_sum = nums[0];
    let mut cur_sum = nums[0];
    let mut best_end = 0;
    v.ptrs(
        &[(0, HighlightKind::Active)],
        &[(0, "i")],
        format!("cur={} max={}", cur_sum, max_sum),
    );
    for i in 1..n {
        if cur_sum + nums[i] > nums[i] {
            cur_sum += nums[i];
        } else {
            cur_sum = nums[i];
        }
        if cur_sum > max_sum {
            max_sum = cur_sum;
            best_end = i;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={}: extend or restart? cur_sum={}. Extending is better if cur_sum + nums[i] > nums[i]. Global max = {}.", i, nums[i], cur_sum, max_sum),
        );
    }
    v.ptrs(
        &[(best_end, HighlightKind::Found)],
        &[(best_end, "end")],
        format!(
            "Answer: maximum subarray sum = {}. Time: O(n), Space: O(1).",
            max_sum
        ),
    );
    v.into_frames()
}

fn viz_dp_longest_increasing_subsequence() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let nums = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(nums.clone());
    v.ptrs(&[], &[], format!("Goal: Find the length of the Longest Increasing Subsequence. Strategy: DP where dp[i] = length of LIS ending at index i. For each i, check all j < i: if nums[j] < nums[i], dp[i] = max(dp[i], dp[j]+1). Array: {:?}", nums));

    let mut dp = vec![1i32; n];
    for i in 1..n {
        for j in 0..i {
            if nums[j] < nums[i] && dp[j] + 1 > dp[i] {
                dp[i] = dp[j] + 1;
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Comparing)],
                    &[(i, "i"), (j, "j")],
                    format!(
                        "[{}]={} > [{}]={} dp[{}]={}",
                        i, nums[i], j, nums[j], i, dp[i]
                    ),
                );
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Sorted)],
            &[(i, "i")],
            format!("dp[{}]={}", i, dp[i]),
        );
    }
    let lis = *dp.iter().max().unwrap_or(&1);
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: LIS length = {}", lis),
    );
    v.into_frames()
}

fn viz_dp_longest_common_subsequence() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let na = rng.random_range(4..=6);
    let nb = rng.random_range(4..=6);
    let a = rand_arr(&mut rng, na, 1, 5);
    let b = rand_arr(&mut rng, nb, 1, 5);
    let display_len = na.max(nb).min(8);
    let mut display = vec![0i32; display_len];
    let copy_len = na.min(display_len);
    display[..copy_len].copy_from_slice(&a[..copy_len]);
    let mut v = VizLog::new(display);
    v.ptrs(&[], &[], format!("Goal: Find the Longest Common Subsequence of two sequences. Strategy: 2D DP where dp[i][j] = LCS length of a[0..i] and b[0..j]. If a[i]==b[j], extend; else take max of skipping either. a={:?}, b={:?}", a, b));

    let mut dp = vec![vec![0i32; nb + 1]; na + 1];
    for i in 1..=na {
        for j in 1..=nb {
            if a[i - 1] == b[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = dp[i - 1][j].max(dp[i][j - 1]);
            }
        }
        let idx = (i - 1).min(display_len - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!(
                "Row {}: a[{}]={} best so far={}",
                i,
                i - 1,
                a[i - 1],
                dp[i][nb]
            ),
        );
    }
    let hl: Vec<_> = (0..display_len)
        .map(|i| (i, HighlightKind::Sorted))
        .collect();
    v.ptrs(
        &hl,
        &[],
        format!(
            "Answer: LCS length = {}. Time: O(n*m), Space: O(n*m).",
            dp[na][nb]
        ),
    );
    v.into_frames()
}

fn viz_dp_regular_expression() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let slen = rng.random_range(4..=6);
    let s: String = (0..slen).map(|_| letters[rng.random_range(0..2)]).collect();
    let p = format!("{}.*{}", &s[..1], &s[slen - 1..]);
    let n = slen.min(8);
    let arr: Vec<i32> = s.chars().map(|c| c as i32 - 'a' as i32 + 1).collect();
    let mut v = VizLog::new(arr[..n].to_vec());
    v.ptrs(&[], &[], format!("Goal: Check if s matches regex p using DP. Strategy: dp[i][j] = s[0..i] matches p[0..j]. Handle '.' (any char) and '*' (0+ of previous). s=\"{}\", p=\"{}\"", s, p));

    let sc: Vec<char> = s.chars().collect();
    let pc: Vec<char> = p.chars().collect();
    let m = pc.len();
    let mut dp = vec![vec![false; m + 1]; n + 1];
    dp[0][0] = true;
    for j in 1..=m {
        if pc[j - 1] == '*' && j >= 2 {
            dp[0][j] = dp[0][j - 2];
        }
    }
    for i in 1..=n {
        for j in 1..=m {
            if pc[j - 1] == '.' || pc[j - 1] == sc[i - 1] {
                dp[i][j] = dp[i - 1][j - 1];
            } else if pc[j - 1] == '*' && j >= 2 {
                dp[i][j] =
                    dp[i][j - 2] || ((pc[j - 2] == '.' || pc[j - 2] == sc[i - 1]) && dp[i - 1][j]);
            }
        }
        let idx = (i - 1).min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("Row {} match so far={}", i, dp[i][m]),
        );
    }
    let result = dp[n][m];
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Answer: regex match = {}. Time: O(n*m).", result),
    );
    v.into_frames()
}

fn viz_dp_longest_valid_parentheses() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let parens: Vec<i32> = (0..n)
        .map(|_| if rng.random_range(0..2) == 0 { 1 } else { 2 })
        .collect();
    let mut v = VizLog::new(parens.clone());
    v.ptrs(
        &[],
        &[],
        format!(
            "Longest Valid Parens — {} (1='(' 2=')')",
            parens
                .iter()
                .map(|&x| if x == 1 { '(' } else { ')' })
                .collect::<String>()
        ),
    );

    let mut dp = vec![0i32; n];
    let mut max_len = 0i32;
    for i in 1..n {
        if parens[i] == 2 {
            if parens[i - 1] == 1 {
                dp[i] = if i >= 2 { dp[i - 2] } else { 0 } + 2;
            } else if dp[i - 1] > 0 {
                let j = i as i32 - dp[i - 1] - 1;
                if j >= 0 && parens[j as usize] == 1 {
                    dp[i] = dp[i - 1] + 2 + if j >= 1 { dp[j as usize - 1] } else { 0 };
                }
            }
            if dp[i] > max_len {
                max_len = dp[i];
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("dp[{}]={} max={}", i, dp[i], max_len),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: longest valid parentheses = {}. Time: O(n).",
            max_len
        ),
    );
    v.into_frames()
}

// ─── Divide & Conquer ────────────────────────────────────────

fn viz_divide_conquer_binary_search() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let mut arr = rand_unique(&mut rng, n, 1, 30);
    arr.sort();
    let target_idx = rng.random_range(0..n);
    let target = arr[target_idx];
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find target={} in sorted array. Strategy: Divide and conquer via binary search -- compare target to midpoint, eliminate half the array each step. O(log n).", target));

    let mut lo = 0usize;
    let mut hi = n - 1;
    while lo <= hi {
        let mid = (lo + hi) / 2;
        v.ptrs(
            &[
                (lo, HighlightKind::Active),
                (mid, HighlightKind::Pivot),
                (hi, HighlightKind::Active),
            ],
            &[(lo, "lo"), (mid, "mid"), (hi, "hi")],
            format!("Check mid={} val={}", mid, arr[mid]),
        );
        if arr[mid] == target {
            v.ptrs(
                &[(mid, HighlightKind::Found)],
                &[(mid, "mid")],
                format!("Found {} at index {}", target, mid),
            );
            break;
        } else if arr[mid] < target {
            lo = mid + 1;
        } else {
            if mid == 0 {
                break;
            }
            hi = mid - 1;
        }
    }
    v.into_frames()
}

fn viz_divide_conquer_find_peak() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let mut arr = rand_arr(&mut rng, n, 1, 20);
    let peak = rng.random_range(1..n - 1);
    arr.sort();
    arr[peak..].reverse();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find a peak element (greater than neighbors). Strategy: Binary search -- if arr[mid] < arr[mid+1], peak is to the right; otherwise to the left. O(log n). Array: {:?}", arr));

    let mut lo = 0usize;
    let mut hi = n - 1;
    while lo < hi {
        let mid = (lo + hi) / 2;
        v.ptrs(
            &[
                (lo, HighlightKind::Active),
                (mid, HighlightKind::Pivot),
                (hi, HighlightKind::Active),
            ],
            &[(lo, "lo"), (mid, "mid"), (hi, "hi")],
            format!("[{}]={} vs [{}]={}", mid, arr[mid], mid + 1, arr[mid + 1]),
        );
        if arr[mid] < arr[mid + 1] {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    v.ptrs(
        &[(lo, HighlightKind::Found)],
        &[(lo, "peak")],
        format!("Peak at index {} val={}", lo, arr[lo]),
    );
    v.into_frames()
}

fn viz_divide_conquer_different_ways() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let arr = rand_arr(&mut rng, n, 1, 8);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Different Ways to Add Parens — {:?}", arr),
    );

    for split in 1..n {
        let left: i32 = arr[..split].iter().sum();
        let right: i32 = arr[split..].iter().sum();
        v.ptrs(
            &[
                (split - 1, HighlightKind::Active),
                (split, HighlightKind::Pivot),
            ],
            &[(split - 1, "L"), (split, "R")],
            format!("Split at {} — left_sum={} right_sum={}", split, left, right),
        );
    }
    let total: i32 = arr.iter().sum();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: total={} with various groupings", total),
    );
    v.into_frames()
}

fn viz_divide_conquer_count_range_sum() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, -5, 10);
    let lower = rng.random_range(-3..=0);
    let upper = rng.random_range(5..=10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Count Range Sum [{},{}] — {:?}", lower, upper, arr),
    );

    let mut prefix = vec![0i64; n + 1];
    for i in 0..n {
        prefix[i + 1] = prefix[i] + arr[i] as i64;
    }

    let mut count = 0u32;
    for i in 0..n {
        for j in i..n {
            let s = prefix[j + 1] - prefix[i];
            if s >= lower as i64 && s <= upper as i64 {
                count += 1;
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Found)],
                    &[(i, "i"), (j, "j")],
                    format!("sum[{},{}]={} in range", i, j, s),
                );
            }
        }
        if count > 8 {
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} range sums in [{},{}]", count, lower, upper),
    );
    v.into_frames()
}

fn viz_divide_conquer_reverse_pairs() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Count reverse pairs where arr[i] > 2*arr[j] for i<j. Strategy: Brute force O(n^2) shown here; optimizable to O(n log n) with merge sort. Array: {:?}", arr));

    let mut count = 0u32;
    for i in 0..n {
        for j in i + 1..n {
            if arr[i] as i64 > 2 * arr[j] as i64 {
                count += 1;
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Found)],
                    &[(i, "i"), (j, "j")],
                    format!(
                        "Pair ({},{}) {}>{} (2*{}={})",
                        i,
                        j,
                        arr[i],
                        2 * arr[j],
                        arr[j],
                        2 * arr[j]
                    ),
                );
            }
        }
        if count > 8 {
            break;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: {} reverse pairs found. Time: O(n^2) brute force, O(n log n) with merge sort.",
            count
        ),
    );
    v.into_frames()
}

// ─── Intervals ───────────────────────────────────────────────

fn viz_intervals_meeting_rooms() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=12);
            (a, a + rng.random_range(1..=3))
        })
        .collect();
    intervals.sort_by_key(|x| x.0);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Determine if a person can attend all meetings (no overlaps). Strategy: Sort meetings by start time, check if any meeting starts before the previous one ends.");

    let mut can_attend = true;
    for i in 1..n {
        let idx = (2 * i).min(arr_len - 1);
        if intervals[i].0 < intervals[i - 1].1 {
            can_attend = false;
            v.ptrs(
                &[(idx, HighlightKind::Swapping)],
                &[(idx, "i")],
                format!(
                    "Overlap: [{},{}] and [{},{}]",
                    intervals[i - 1].0,
                    intervals[i - 1].1,
                    intervals[i].0,
                    intervals[i].1
                ),
            );
            break;
        }
        v.ptrs(
            &[(idx, HighlightKind::Found)],
            &[(idx, "i")],
            format!("[{},{}] ok", intervals[i].0, intervals[i].1),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: can attend all = {}. Time: O(n log n) for sorting.",
            can_attend
        ),
    );
    v.into_frames()
}

fn viz_intervals_covered_length() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.0);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the total length covered by the union of intervals. Strategy: Sort by start, sweep left-to-right. Extend the current segment or start a new one when gaps appear.");

    let mut total = 0i32;
    let mut cur_end = i32::MIN;
    for i in 0..n {
        let (s, e) = intervals[i];
        let idx = (2 * i).min(arr_len - 1);
        if s > cur_end {
            total += e - s;
            cur_end = e;
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("New segment [{},{}] total={}", s, e, total),
            );
        } else if e > cur_end {
            total += e - cur_end;
            cur_end = e;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Extend to {} total={}", e, total),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Sorted)],
                &[(idx, "i")],
                format!("[{},{}] fully covered", s, e),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: total covered length = {}. Time: O(n log n) for sorting + O(n) sweep.",
            total
        ),
    );
    v.into_frames()
}

fn viz_intervals_meeting_rooms_ii() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.0);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find the minimum number of meeting rooms needed. Strategy: Sort by start time, use a min-heap of end times. Reuse a room if its meeting ended, otherwise allocate a new room.");

    let mut ends: Vec<i32> = Vec::new();
    let mut max_rooms = 0usize;
    for i in 0..n {
        let (s, e) = intervals[i];
        let idx = (2 * i).min(arr_len - 1);
        ends.sort();
        if let Some(pos) = ends.iter().position(|&end| end <= s) {
            ends.remove(pos);
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("[{},{}] reuse room (rooms={})", s, e, ends.len() + 1),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("[{},{}] new room (rooms={})", s, e, ends.len() + 1),
            );
        }
        ends.push(e);
        max_rooms = max_rooms.max(ends.len());
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: {} meeting rooms needed. Peak concurrency determines the answer. O(n log n).",
            max_rooms
        ),
    );
    v.into_frames()
}

fn viz_intervals_non_overlapping() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.1);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Remove the minimum number of intervals to make the rest non-overlapping. Strategy: Sort by end time, greedily keep intervals that start after the last kept interval ends.");

    let mut end = i32::MIN;
    let mut keep = 0;
    for i in 0..n {
        let (s, e) = intervals[i];
        let idx = (2 * i).min(arr_len - 1);
        if s >= end {
            keep += 1;
            end = e;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Keep [{},{}] (count={})", s, e, keep),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Swapping)],
                &[(idx, "i")],
                format!("Remove [{},{}] overlaps", s, e),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: remove {} intervals (keep {}). Time: O(n log n) for sorting.",
            n as i32 - keep,
            keep
        ),
    );
    v.into_frames()
}

fn viz_intervals_min_arrows() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=10);
            (a, a + rng.random_range(1..=4))
        })
        .collect();
    intervals.sort_by_key(|x| x.1);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Find minimum arrows to burst all balloons (intervals). Strategy: Sort by end. Shoot at each first un-burst balloon's end point -- this pops all overlapping balloons.");

    let mut arrows = 0;
    let mut arrow_pos = i32::MIN;
    for i in 0..n {
        let (s, e) = intervals[i];
        let idx = (2 * i).min(arr_len - 1);
        if s > arrow_pos {
            arrows += 1;
            arrow_pos = e;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Arrow {} at {} for [{},{}]", arrows, e, s, e),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("[{},{}] burst by arrow at {}", s, e, arrow_pos),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} arrows needed", arrows),
    );
    v.into_frames()
}

fn viz_intervals_interval_intersection() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let na = rng.random_range(3..=4);
    let nb = rng.random_range(3..=4);
    let mut a_ivs: Vec<(i32, i32)> = Vec::new();
    let mut b_ivs: Vec<(i32, i32)> = Vec::new();
    let mut pos = 1;
    for _ in 0..na {
        let s = pos;
        let e = s + rng.random_range(1..=3);
        a_ivs.push((s, e));
        pos = e + rng.random_range(1..=2);
    }
    pos = rng.random_range(1..=3);
    for _ in 0..nb {
        let s = pos;
        let e = s + rng.random_range(1..=3);
        b_ivs.push((s, e));
        pos = e + rng.random_range(1..=2);
    }
    let arr: Vec<i32> = a_ivs.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(8);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(
        &[],
        &[],
        format!("Interval Intersection A={:?} B={:?}", a_ivs, b_ivs),
    );

    let mut ai = 0usize;
    let mut bi = 0usize;
    let mut result: Vec<(i32, i32)> = Vec::new();
    while ai < na && bi < nb {
        let lo = a_ivs[ai].0.max(b_ivs[bi].0);
        let hi = a_ivs[ai].1.min(b_ivs[bi].1);
        let idx = (2 * ai).min(arr_len - 1);
        if lo <= hi {
            result.push((lo, hi));
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Intersect [{},{}]", lo, hi),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "i")],
                format!("No overlap A={:?} B={:?}", a_ivs[ai], b_ivs[bi]),
            );
        }
        if a_ivs[ai].1 < b_ivs[bi].1 {
            ai += 1;
        } else {
            bi += 1;
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {:?}", result),
    );
    v.into_frames()
}

fn viz_intervals_my_calendar() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut booked: Vec<(i32, i32)> = Vec::new();
    let mut events: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=12);
            (a, a + rng.random_range(1..=3))
        })
        .collect();
    let arr: Vec<i32> = events.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Book events without double-booking. Strategy: For each new event, check against all existing bookings for overlap. If no conflict, add it. O(n) per booking.");

    for i in 0..n {
        let (s, e) = events[i];
        let idx = (2 * i).min(arr_len - 1);
        let conflict = booked.iter().any(|&(bs, be)| s < be && e > bs);
        if conflict {
            v.ptrs(
                &[(idx, HighlightKind::Swapping)],
                &[(idx, "i")],
                format!("[{},{}] conflicts — rejected", s, e),
            );
        } else {
            booked.push((s, e));
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("[{},{}] booked (total={})", s, e, booked.len()),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Answer: {} events booked. Time: O(n^2) with linear scan per booking.",
            booked.len()
        ),
    );
    v.into_frames()
}

fn viz_intervals_max_events() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|_| {
            let a = rng.random_range(1..=8);
            (a, a + rng.random_range(0..=2))
        })
        .collect();
    intervals.sort_by_key(|x| x.1);
    let arr: Vec<i32> = intervals.iter().flat_map(|&(a, b)| vec![a, b]).collect();
    let arr_len = arr.len().min(10);
    let mut v = VizLog::new(arr[..arr_len].to_vec());
    v.ptrs(&[], &[], "Goal: Attend the maximum number of events (each takes 1 day). Strategy: Sort by end day, greedily attend each event on the earliest available day within its range.");

    let mut attended = 0;
    let mut last_day = 0i32;
    for i in 0..n {
        let (s, e) = intervals[i];
        let day = s.max(last_day + 1);
        let idx = (2 * i).min(arr_len - 1);
        if day <= e {
            attended += 1;
            last_day = day;
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "i")],
                format!("Attend [{},{}] on day {} (count={})", s, e, day, attended),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Swapping)],
                &[(idx, "i")],
                format!("[{},{}] cannot attend", s, e),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Answer: {} events attended. Time: O(n log n).", attended),
    );
    v.into_frames()
}

// ─── Segment / Fenwick ───────────────────────────────────────

fn viz_segment_point_update() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let mut arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Update a single element and query range sums. Strategy: Segment tree -- update propagates up O(log n) nodes, range query merges O(log n) nodes.");

    let idx = rng.random_range(0..n);
    let new_val = rng.random_range(11..=20);
    let old = arr[idx];
    arr[idx] = new_val;
    v.ptrs(
        &[(idx, HighlightKind::Swapping)],
        &[(idx, "node")],
        format!("Update [{}]: {} -> {}", idx, old, new_val),
    );

    let mut node = idx + n;
    while node > 1 {
        node /= 2;
        let display = node.min(n - 1);
        v.ptrs(
            &[(display, HighlightKind::Active)],
            &[(display, "node")],
            format!("Propagate to node {}", node),
        );
    }

    v.array = arr.clone();
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Updated: {:?}", arr));
    v.into_frames()
}

fn viz_segment_range_update_point_query() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Add a value to all elements in a range, then query individual elements. Strategy: Use a difference array or segment tree with lazy propagation. Update O(log n), query O(log n).");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let add_val = rng.random_range(1..=5);
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Active)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Range update [{},{}] += {}", l, r, add_val),
    );

    let mut updated = arr.clone();
    for i in l..=r {
        updated[i] += add_val;
        v.ptrs(
            &[(i, HighlightKind::Found)],
            &[(i, "i")],
            format!("[{}]: {} -> {}", i, arr[i], updated[i]),
        );
    }
    v.array = updated.clone();
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Updated: {:?}", updated));
    v.into_frames()
}

fn viz_segment_count_smaller_after() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: For each element, count how many smaller elements appear after it. Strategy: Process right-to-left, inserting values into a segment tree (as BIT over values) to count elements smaller than current. O(n log n).");

    let mut result = vec![0i32; n];
    for i in (0..n).rev() {
        let count = arr[i + 1..].iter().filter(|&&x| x < arr[i]).count() as i32;
        result[i] = count;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "node")],
            format!("[{}]={} has {} smaller after", i, arr[i], count),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Result: {:?}", result));
    v.into_frames()
}

fn viz_fenwick_2d_sum() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Compute prefix sums and range sum queries efficiently. Strategy: Build prefix sum array in O(n). Range sum [l,r] = prefix[r+1] - prefix[l] in O(1).");

    let mut prefix = vec![0i32; n + 1];
    for i in 0..n {
        prefix[i + 1] = prefix[i] + arr[i];
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("prefix[{}]={}", i + 1, prefix[i + 1]),
        );
    }

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let sum = prefix[r + 1] - prefix[l];
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Sum [{},{}] = {}", l, r, sum),
    );
    v.into_frames()
}

fn viz_fenwick_range_update_range_query() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 8);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Support both range updates (add to a range) and range sum queries. Strategy: Use two Fenwick trees to maintain coefficients for the identity: sum[1..x] = B1[x]*x - B2[x]. O(log n) per operation.");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let add = rng.random_range(2..=5);
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Active)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Add {} to range [{},{}]", add, l, r),
    );

    let mut updated = arr.clone();
    for i in l..=r {
        updated[i] += add;
    }
    v.array = updated.clone();
    let hl2: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(&hl2, &[(l, "L"), (r, "R")], format!("After: {:?}", updated));

    let ql = rng.random_range(0..n / 2);
    let qr = rng.random_range(n / 2..n);
    let sum: i32 = updated[ql..=qr].iter().sum();
    let hl3: Vec<_> = (ql..=qr).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(
        &hl3,
        &[(ql, "qL"), (qr, "qR")],
        format!("Query sum [{},{}] = {}", ql, qr, sum),
    );
    v.into_frames()
}

fn viz_segment_max_subarray_range() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, -5, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the maximum subarray sum within a given range. Strategy: Segment tree where each node stores: total sum, max prefix, max suffix, and max subarray. Merge in O(1), query in O(log n).");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Active)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("Query range [{},{}]", l, r),
    );

    let mut max_sum = i32::MIN;
    let mut cur_sum = 0;
    let mut best_end = l;
    for i in l..=r {
        cur_sum += arr[i];
        if cur_sum > max_sum {
            max_sum = cur_sum;
            best_end = i;
        }
        if cur_sum < 0 {
            cur_sum = 0;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} cur={} max={}", i, arr[i], cur_sum, max_sum),
        );
    }
    v.ptrs(
        &[(best_end, HighlightKind::Found)],
        &[(best_end, "end")],
        format!("Result: max subarray in range = {}", max_sum),
    );
    v.into_frames()
}

// ─── Sparse Tables ───────────────────────────────────────────

fn viz_sparse_table_static_rmq() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Answer range minimum queries on a static array in O(1). Strategy: Build sparse table in O(n log n). Query with two overlapping power-of-2 ranges. Works because min is idempotent.");

    let log_n = (n as f64).log2().floor() as usize + 1;
    let mut table = vec![vec![0i32; n]; log_n];
    table[0][..n].copy_from_slice(&arr[..n]);
    for j in 1..log_n {
        for i in 0..n {
            if i + (1 << j) <= n {
                table[j][i] = table[j - 1][i].min(table[j - 1][i + (1 << (j - 1))]);
            }
        }
        let idx = j.min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "j")],
            format!("Built level {} (len={})", j, 1 << j),
        );
    }

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let min_val = *arr[l..=r].iter().min().unwrap();
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("RMQ [{},{}] = {}", l, r, min_val),
    );
    v.into_frames()
}

fn viz_sparse_table_lca() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let depth: Vec<i32> = (0..n).map(|i| (i as i32) % 4).collect();
    let mut v = VizLog::new(depth.clone());
    v.ptrs(&[], &[], "Goal: Find LCA of two nodes in O(1). Strategy: Flatten tree via Euler tour, record depths. LCA = node with minimum depth between first appearances of the two query nodes. RMQ via sparse table.");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let (min_val, min_idx) = depth[l..=r]
        .iter()
        .enumerate()
        .min_by_key(|&(_, &val)| val)
        .map(|(i, &val)| (val, l + i))
        .unwrap();

    for i in l..=r {
        let kind = if i == min_idx {
            HighlightKind::Found
        } else {
            HighlightKind::Active
        };
        v.ptrs(
            &[(i, kind)],
            &[(i, "i")],
            format!("depth[{}]={}", i, depth[i]),
        );
    }
    v.ptrs(
        &[(min_idx, HighlightKind::Found)],
        &[(min_idx, "lca")],
        format!("LCA at Euler index {} depth={}", min_idx, min_val),
    );
    v.into_frames()
}

fn viz_sparse_table_second_minimum() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the second smallest element in the array. Strategy: Single pass tracking two minimums. When a new element is smaller than the current min, previous min becomes second min. O(n).");

    let mut first = i32::MAX;
    let mut second = i32::MAX;
    let mut first_idx = 0;
    let mut second_idx = 0;
    for i in 0..n {
        if arr[i] < first {
            second = first;
            second_idx = first_idx;
            first = arr[i];
            first_idx = i;
        } else if arr[i] < second && arr[i] != first {
            second = arr[i];
            second_idx = i;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} min1={} min2={}", i, arr[i], first, second),
        );
    }
    v.ptrs(
        &[
            (first_idx, HighlightKind::Found),
            (second_idx, HighlightKind::Sorted),
        ],
        &[(first_idx, "1st"), (second_idx, "2nd")],
        format!("Result: 2nd minimum = {}", second),
    );
    v.into_frames()
}

fn viz_sparse_table_index_of_min() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the index of the minimum element in a range. Strategy: Sparse table storing indices. Query returns the index (not value) of the minimum. O(1) query after O(n log n) build.");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let (min_idx, min_val) = arr[l..=r]
        .iter()
        .enumerate()
        .min_by_key(|&(_, &val)| val)
        .map(|(i, &val)| (l + i, val))
        .unwrap();

    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Active)).collect();
    v.ptrs(&hl, &[(l, "L"), (r, "R")], format!("Query [{},{}]", l, r));

    v.ptrs(
        &[(min_idx, HighlightKind::Found)],
        &[(min_idx, "min")],
        format!("Min at index {} val={}", min_idx, min_val),
    );
    v.into_frames()
}

fn viz_sparse_table_2d_rmq() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the minimum element in a range of a flattened 2D grid. Strategy: Linear scan through the range tracking running minimum. O(range_length) per query.");

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let mut min_val = i32::MAX;
    for i in l..=r {
        if arr[i] < min_val {
            min_val = arr[i];
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} running_min={}", i, arr[i], min_val),
        );
    }
    let hl: Vec<_> = (l..=r).map(|i| (i, HighlightKind::Found)).collect();
    v.ptrs(
        &hl,
        &[(l, "L"), (r, "R")],
        format!("2D RMQ [{},{}] = {}", l, r, min_val),
    );
    v.into_frames()
}

fn viz_sparse_table_range_frequency() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let arr = rand_arr(&mut rng, n, 1, 5);
    let target = arr[rng.random_range(0..n)];
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Count occurrences of {} in a range. Strategy: Linear scan counting matches. Optimizable to O(log n) with sorted occurrence lists + binary search. Array: {:?}", target, arr),
    );

    let l = rng.random_range(0..n / 2);
    let r = rng.random_range(n / 2..n);
    let mut count = 0;
    for i in l..=r {
        if arr[i] == target {
            count += 1;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("[{}]={} match! count={}", i, arr[i], count),
            );
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("[{}]={} skip", i, arr[i]),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!(
            "Result: {} appears {} times in [{},{}]",
            target, count, l, r
        ),
    );
    v.into_frames()
}

fn viz_sparse_table_longest_common_prefix_array() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 5);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Compute the Longest Common Prefix array between consecutive suffixes in sorted order. Strategy: Compare each pair of adjacent sorted suffixes character by character. O(n^2) naive, O(n) with Kasai's algorithm.");

    let mut lcp = vec![0i32; n];
    for i in 1..n {
        let mut len = 0i32;
        let mut j = 0;
        while i + j < n && j < n && arr[j] == arr[i + j] {
            len += 1;
            j += 1;
        }
        lcp[i] = len;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("lcp[{}]={} (prefix match len)", i, lcp[i]),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("LCP array: {:?}", lcp));
    v.into_frames()
}

// ─── Monotonic Stacks/Queues ─────────────────────────────────

fn viz_monotonic_next_smaller() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let nums = rand_arr(&mut rng, n, 1, 20);
    let mut v = VizLog::new(nums.clone());
    v.ptrs(&[], &[], "Goal: For each element, find the next smaller element to its right. Strategy: Monotonic increasing stack. When a smaller element arrives, pop and record it as the next smaller for popped elements. O(n).");

    let mut stack: Vec<usize> = Vec::new();
    let mut result = vec![-1i32; n];
    for i in 0..n {
        while let Some(&top_idx) = stack.last() {
            if nums[top_idx] > nums[i] {
                stack.pop();
                result[top_idx] = nums[i];
                v.ptrs(
                    &[(top_idx, HighlightKind::Found), (i, HighlightKind::Active)],
                    &[(top_idx, "pop"), (i, "cur")],
                    format!("Next smaller of {}={}", nums[top_idx], nums[i]),
                );
            } else {
                break;
            }
        }
        stack.push(i);
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "top")],
            format!("Push [{}]={}", i, nums[i]),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Result: {:?}", result));
    v.into_frames()
}

fn viz_monotonic_maximal_rectangle() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let heights = rand_arr(&mut rng, n, 0, 6);
    let mut v = VizLog::new(heights.clone());
    v.ptrs(&[], &[], "Goal: Find the largest rectangle in a histogram row. Strategy: Monotonic increasing stack -- when a shorter bar arrives, pop taller bars and compute their maximum rectangle width. O(n).");

    let mut stack: Vec<usize> = Vec::new();
    let mut max_area = 0i32;
    for i in 0..=n {
        let h = if i < n { heights[i] } else { 0 };
        while let Some(&top) = stack.last() {
            if heights[top] >= h {
                stack.pop();
                let w = if let Some(&prev) = stack.last() {
                    i - prev - 1
                } else {
                    i
                };
                let area = heights[top] * w as i32;
                max_area = max_area.max(area);
                let idx = top.min(n - 1);
                v.ptrs(
                    &[(idx, HighlightKind::Active)],
                    &[(idx, "top")],
                    format!(
                        "Pop h={} w={} area={} max={}",
                        heights[top], w, area, max_area
                    ),
                );
            } else {
                break;
            }
        }
        if i < n {
            stack.push(i);
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "top")],
                format!("Push [{}]={}", i, heights[i]),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: max rectangle = {}", max_area),
    );
    v.into_frames()
}

fn viz_monotonic_sum_of_subarray_minimums() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Sum the minimums of all subarrays. Strategy: Brute force -- for each starting index, expand right tracking running min and accumulate. O(n^2).");

    let mut total = 0i64;
    for i in 0..n {
        let mut min_val = arr[i];
        for j in i..n {
            min_val = min_val.min(arr[j]);
            total += min_val as i64;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("Subarrays starting at {} — running total={}", i, total),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: sum of mins = {}", total),
    );
    v.into_frames()
}

fn viz_monotonic_sliding_window_min() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(7..=9);
    let nums = rand_arr(&mut rng, n, 1, 15);
    let k = rng.random_range(2..=3);
    let mut v = VizLog::new(nums.clone());
    v.ptrs(&[], &[], format!("Goal: Find minimum in each sliding window of size k={}. Strategy: Monotonic increasing deque. Front is always the window min. Remove elements leaving the window or dominated by the new element. O(n).", k));

    let mut deq: VecDeque<usize> = VecDeque::new();
    let mut result: Vec<i32> = Vec::new();
    for i in 0..n {
        while let Some(&back) = deq.back() {
            if nums[back] >= nums[i] {
                deq.pop_back();
            } else {
                break;
            }
        }
        deq.push_back(i);
        if let Some(&front) = deq.front() {
            if front + k <= i {
                deq.pop_front();
            }
        }
        if i + 1 >= k {
            let min_val = nums[*deq.front().unwrap()];
            result.push(min_val);
            let lo = i + 1 - k;
            let hl: Vec<_> = (lo..=i).map(|j| (j, HighlightKind::Active)).collect();
            v.ptrs(
                &hl,
                &[(lo, "L"), (i, "R")],
                format!("Window [{},{}] min={}", lo, i, min_val),
            );
        }
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Result: {:?}", result));
    v.into_frames()
}

fn viz_monotonic_sum_subarray_ranges() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let arr = rand_arr(&mut rng, n, 1, 10);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Sum (max - min) for all subarrays. Strategy: For each subarray, track running min and max. Sum of ranges = sum_of_maxes - sum_of_mins. O(n^2) brute force.");

    let mut total = 0i64;
    for i in 0..n {
        let mut min_val = arr[i];
        let mut max_val = arr[i];
        for j in i..n {
            min_val = min_val.min(arr[j]);
            max_val = max_val.max(arr[j]);
            total += (max_val - min_val) as i64;
            if j > i {
                v.ptrs(
                    &[(i, HighlightKind::Active), (j, HighlightKind::Active)],
                    &[(i, "i"), (j, "j")],
                    format!(
                        "[{},{}] range={}-{}={} total={}",
                        i,
                        j,
                        max_val,
                        min_val,
                        max_val - min_val,
                        total
                    ),
                );
            }
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: sum of ranges = {}", total),
    );
    v.into_frames()
}

// ─── Bit Manipulation ────────────────────────────────────────

fn viz_bits_is_power_of_two() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 16);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Check which numbers are powers of 2. Strategy: n & (n-1) == 0 for powers of 2 (they have exactly one set bit). n-1 flips all lower bits, so AND gives 0.");

    for i in 0..n {
        let is_pow2 = arr[i] > 0 && (arr[i] & (arr[i] - 1)) == 0;
        let kind = if is_pow2 {
            HighlightKind::Found
        } else {
            HighlightKind::Active
        };
        v.ptrs(
            &[(i, kind)],
            &[(i, "i")],
            format!(
                "[{}]={} ({:04b}) — {}",
                i,
                arr[i],
                arr[i],
                if is_pow2 { "YES" } else { "no" }
            ),
        );
    }
    v.into_frames()
}

fn viz_bits_sum_without_arithmetic() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Add two numbers without using + or -. Strategy: XOR gives the sum without carries. AND << 1 gives the carries. Repeat until no carries remain. O(log(max_val)) iterations.");

    for i in 0..n - 1 {
        let mut a = arr[i];
        let mut b = arr[i + 1];
        let orig_a = a;
        let orig_b = b;
        let mut steps = 0;
        while b != 0 && steps < 8 {
            let carry = a & b;
            a ^= b;
            b = carry << 1;
            steps += 1;
        }
        v.ptrs(
            &[(i, HighlightKind::Active), (i + 1, HighlightKind::Active)],
            &[(i, "a"), (i + 1, "b")],
            format!(
                "{}+{} = {} (via {} XOR/AND steps)",
                orig_a, orig_b, a, steps
            ),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        "Done: all sums computed without +".to_string(),
    );
    v.into_frames()
}

fn viz_bits_maximum_xor() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find max XOR of any pair. Strategy: Brute force all pairs O(n^2). Optimizable to O(n*32) with trie to greedily pick opposite bits.");

    let mut max_xor = 0i32;
    let mut best_i = 0;
    let mut best_j = 0;
    for i in 0..n {
        for j in i + 1..n {
            let xor = arr[i] ^ arr[j];
            if xor > max_xor {
                max_xor = xor;
                best_i = i;
                best_j = j;
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} best XOR so far={}", i, arr[i], max_xor),
        );
    }
    v.ptrs(
        &[
            (best_i, HighlightKind::Found),
            (best_j, HighlightKind::Found),
        ],
        &[(best_i, "a"), (best_j, "b")],
        format!("Result: {} XOR {} = {}", arr[best_i], arr[best_j], max_xor),
    );
    v.into_frames()
}

fn viz_bits_max_and_pair() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the maximum bitwise AND of any pair. Strategy: Brute force all pairs. AND can only keep bits both numbers share, so larger numbers with shared high bits give best results. O(n^2).");

    let mut max_and = 0i32;
    let mut best_i = 0;
    let mut best_j = 1;
    for i in 0..n {
        for j in i + 1..n {
            let and = arr[i] & arr[j];
            if and > max_and {
                max_and = and;
                best_i = i;
                best_j = j;
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} ({:04b}) best AND={}", i, arr[i], arr[i], max_and),
        );
    }
    v.ptrs(
        &[
            (best_i, HighlightKind::Found),
            (best_j, HighlightKind::Found),
        ],
        &[(best_i, "a"), (best_j, "b")],
        format!("Result: {} & {} = {}", arr[best_i], arr[best_j], max_and),
    );
    v.into_frames()
}

fn viz_bits_min_flips() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 0, 15);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Count minimum bit flips to convert between consecutive elements. Strategy: XOR the two numbers -- set bits in the XOR represent positions that differ. Count them with popcount. O(1) per pair.");

    for i in 0..n - 1 {
        let xor = arr[i] ^ arr[i + 1];
        let flips = xor.count_ones();
        v.ptrs(
            &[(i, HighlightKind::Active), (i + 1, HighlightKind::Active)],
            &[(i, "a"), (i + 1, "b")],
            format!(
                "{} ({:04b}) -> {} ({:04b}) = {} flips",
                arr[i],
                arr[i],
                arr[i + 1],
                arr[i + 1],
                flips
            ),
        );
    }
    let total: u32 = (0..n - 1).map(|i| (arr[i] ^ arr[i + 1]).count_ones()).sum();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} total flips", total),
    );
    v.into_frames()
}

// ─── String Algorithms ───────────────────────────────────────

fn viz_string_algo_count_occurrences() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b', 'c'];
    let n = rng.random_range(8..=10);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let text: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let pat_len = 2;
    let pat: String = text[0..pat_len].to_string();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Count occurrences of \"{}\" in \"{}\". Strategy: Slide a window of pattern length across the text, checking for exact match at each position. O(n*m) naive.", pat, text));

    let pat_chars: Vec<char> = pat.chars().collect();
    let text_chars: Vec<char> = text.chars().collect();
    let mut count = 0;
    for i in 0..=n - pat_len {
        let matches = (0..pat_len).all(|j| text_chars[i + j] == pat_chars[j]);
        if matches {
            count += 1;
            let hl: Vec<_> = (i..i + pat_len)
                .map(|j| (j, HighlightKind::Found))
                .collect();
            v.ptrs(&hl, &[(i, "i")], format!("Match #{} at {}", count, i));
        } else {
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("No match at {}", i),
            );
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} occurrences", count),
    );
    v.into_frames()
}

fn viz_string_algo_is_rotation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 5);
    let rot = rng.random_range(1..n);
    let mut rotated = arr[rot..].to_vec();
    rotated.extend_from_slice(&arr[..rot]);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Check if rotated is a rotation of orig. Strategy: A rotation of s is always a substring of s+s. Alternatively, verify element-by-element with offset. orig={:?}, rotated={:?}", arr, rotated),
    );

    v.ptrs(
        &[(rot, HighlightKind::Pivot)],
        &[(rot, "rot")],
        format!("Rotation point at index {}", rot),
    );

    for i in 0..n {
        let src = (i + rot) % n;
        let kind = if arr[src] == rotated[i] {
            HighlightKind::Found
        } else {
            HighlightKind::Swapping
        };
        v.ptrs(
            &[(src, kind)],
            &[(src, "src")],
            format!("orig[{}]={} == rot[{}]={}", src, arr[src], i, rotated[i]),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: IS a rotation by {}", rot),
    );
    v.into_frames()
}

fn viz_string_algo_longest_prefix_suffix() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let letters = ['a', 'b'];
    let n = rng.random_range(6..=8);
    let arr: Vec<i32> = (0..n)
        .map(|_| letters[rng.random_range(0..letters.len())] as i32 - 'a' as i32 + 1)
        .collect();
    let s: String = arr
        .iter()
        .map(|&x| (x - 1 + 'a' as i32) as u8 as char)
        .collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Compute KMP failure function (longest proper prefix that is also a suffix). Strategy: Two-pointer technique where len tracks the current matched prefix length. Mismatch falls back via lps[len-1]. String: \"{}\"", s));

    let chars: Vec<char> = s.chars().collect();
    let mut lps = vec![0usize; n];
    let mut len = 0;
    let mut i = 1;
    while i < n {
        if chars[i] == chars[len] {
            len += 1;
            lps[i] = len;
            v.ptrs(
                &[
                    (i, HighlightKind::Found),
                    (len - 1, HighlightKind::Comparing),
                ],
                &[(i, "i"), (len - 1, "len")],
                format!("Match: lps[{}]={}", i, lps[i]),
            );
            i += 1;
        } else if len > 0 {
            len = lps[len - 1];
        } else {
            lps[i] = 0;
            v.ptrs(
                &[(i, HighlightKind::Active)],
                &[(i, "i")],
                format!("lps[{}]=0", i),
            );
            i += 1;
        }
    }
    let max_lps = *lps.iter().max().unwrap_or(&0);
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: longest prefix-suffix = {}", max_lps),
    );
    v.into_frames()
}

fn viz_string_algo_repeated_string_match() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(4..=6);
    let arr = rand_arr(&mut rng, n, 1, 3);
    let repeat_count = rng.random_range(2..=3);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(
        &[],
        &[],
        format!("Repeated String Match — repeat {:?} x{}", arr, repeat_count),
    );

    let mut repeated = arr.clone();
    for r in 1..=repeat_count {
        if r > 1 {
            repeated.extend_from_slice(&arr);
        }
        let idx = (r - 1).min(n - 1);
        v.ptrs(
            &[(idx, HighlightKind::Active)],
            &[(idx, "i")],
            format!("Repeat {} — len={}", r, repeated.len()),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: need {} repeats", repeat_count),
    );
    v.into_frames()
}

fn viz_string_algo_longest_duplicate_substring() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 4);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find the longest substring that appears at least twice. Strategy: Binary search on length + rolling hash (or suffix array). Check all substrings of candidate length for duplicates. O(n^2) brute force shown.");

    let mut best_len = 0;
    let mut best_start = 0;
    for length in (1..n).rev() {
        let mut found = false;
        for i in 0..=n - length {
            for j in i + 1..=n - length {
                if arr[i..i + length] == arr[j..j + length] {
                    if length > best_len {
                        best_len = length;
                        best_start = i;
                    }
                    found = true;
                    break;
                }
            }
            if found {
                break;
            }
        }
        if found {
            let hl: Vec<_> = (best_start..best_start + best_len)
                .map(|i| (i, HighlightKind::Found))
                .collect();
            v.ptrs(&hl, &[(best_start, "i")], format!("Dup len={}", best_len));
            break;
        }
    }
    if best_len == 0 {
        v.ptrs(
            &[],
            &[],
            "No duplicate substring found. All substrings are unique.".to_string(),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: longest dup len={}", best_len),
    );
    v.into_frames()
}

fn viz_string_algo_suffix_array() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 4);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Build a suffix array (sorted indices of all suffixes). Strategy: Generate all suffixes with their starting indices, sort lexicographically. The result maps rank -> start index. O(n^2 log n) naive.");

    let mut suffixes: Vec<(usize, Vec<i32>)> = (0..n).map(|i| (i, arr[i..].to_vec())).collect();
    suffixes.sort_by(|a, b| a.1.cmp(&b.1));

    for (rank, (idx, _suffix)) in suffixes.iter().enumerate() {
        let vi = (*idx).min(n - 1);
        v.ptrs(
            &[(vi, HighlightKind::Active)],
            &[(vi, "i")],
            format!("Rank {}: suffix starting at {}", rank, idx),
        );
    }
    let sa: Vec<usize> = suffixes.iter().map(|(idx, _)| *idx).collect();
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Suffix Array: {:?}", sa),
    );
    v.into_frames()
}

fn viz_string_algo_lcp_array() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 1, 4);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Compute the LCP (Longest Common Prefix) array from a suffix array. Strategy: Compare adjacent suffixes in sorted order character by character. LCP[i] = shared prefix length of SA[i-1] and SA[i]. O(n^2) naive, O(n) with Kasai.");

    let mut suffixes: Vec<(usize, Vec<i32>)> = (0..n).map(|i| (i, arr[i..].to_vec())).collect();
    suffixes.sort_by(|a, b| a.1.cmp(&b.1));

    let mut lcp_arr = vec![0i32; n];
    for i in 1..suffixes.len() {
        let a = &suffixes[i - 1].1;
        let b = &suffixes[i].1;
        let mut l = 0;
        while l < a.len() && l < b.len() && a[l] == b[l] {
            l += 1;
        }
        lcp_arr[i] = l as i32;
        let vi = suffixes[i].0.min(n - 1);
        v.ptrs(
            &[(vi, HighlightKind::Active)],
            &[(vi, "i")],
            format!("LCP[{}]={}", i, l),
        );
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("LCP Array: {:?}", &lcp_arr[..n]),
    );
    v.into_frames()
}

fn viz_string_algo_distinct_substrings() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(4..=6);
    let arr = rand_arr(&mut rng, n, 1, 3);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Count distinct substrings. Strategy: Generate all substrings of all lengths, insert into a HashSet. Count = set size. O(n^3) naive. Suffix array + LCP gives O(n^2) or O(n log n).");

    let mut seen: HashSet<Vec<i32>> = HashSet::new();
    for length in 1..=n {
        for i in 0..=n - length {
            let sub = arr[i..i + length].to_vec();
            let is_new = seen.insert(sub);
            if is_new {
                let end = (i + length - 1).min(n - 1);
                v.ptrs(
                    &[(i, HighlightKind::Found), (end, HighlightKind::Found)],
                    &[(i, "i"), (end, "j")],
                    format!("New substr [{},{}] total={}", i, i + length - 1, seen.len()),
                );
            }
        }
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {} distinct substrings", seen.len()),
    );
    v.into_frames()
}

fn viz_string_algo_palindrome_partitioning_min() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(5..=7);
    let arr = rand_arr(&mut rng, n, 1, 3);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Find minimum cuts to partition string into palindromes. Strategy: DP where dp[i] = min cuts for s[0..=i]. If s[0..=i] is itself a palindrome, dp[i]=0. Otherwise try all split points. O(n^2).");

    let mut dp = vec![0i32; n];
    for i in 0..n {
        dp[i] = i as i32;
    }
    for i in 1..n {
        // Check if whole prefix is palindrome
        let slice = &arr[..=i];
        let is_pal = slice.iter().eq(slice.iter().rev());
        if is_pal {
            dp[i] = 0;
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("[0..{}] is palindrome, dp[{}]=0", i, i),
            );
            continue;
        }
        for j in 0..i {
            let slice = &arr[j + 1..=i];
            let is_pal = slice.iter().eq(slice.iter().rev());
            if is_pal && dp[j] + 1 < dp[i] {
                dp[i] = dp[j] + 1;
            }
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("dp[{}]={} cuts", i, dp[i]),
        );
    }
    v.ptrs(
        &[(n - 1, HighlightKind::Found)],
        &[(n - 1, "i")],
        format!("Result: min cuts = {}", dp[n - 1]),
    );
    v.into_frames()
}

// ─── Math & Geometry ─────────────────────────────────────────

fn viz_math_power_mod() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let base = rng.random_range(2..=5);
    let exp = rng.random_range(4..=8);
    let modulus = rng.random_range(7..=13);
    let arr: Vec<i32> = vec![base, exp, modulus, 0, 0, 0, 0];
    let n = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!("Goal: Compute {}^{} mod {}. Strategy: Binary exponentiation -- square base each step, multiply into result when exponent bit is set. O(log exp) multiplications.", base, exp, modulus),
    );

    let mut result = 1i64;
    let mut b = base as i64;
    let mut e = exp;
    let m = modulus as i64;
    let mut step = 0;
    while e > 0 {
        if e % 2 == 1 {
            result = (result * b) % m;
            let idx = step.min(n - 1);
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "step")],
                format!(
                    "exp odd: result = {} * {} mod {} = {}",
                    result, b, m, result
                ),
            );
        } else {
            let idx = step.min(n - 1);
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "step")],
                format!("exp even: skip multiply, result={}", result),
            );
        }
        b = (b * b) % m;
        e /= 2;
        step += 1;
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: {}^{} mod {} = {}", base, exp, modulus, result),
    );
    v.into_frames()
}

fn viz_math_reverse_integer() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let arr = rand_arr(&mut rng, n, 10, 99);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], "Goal: Reverse the digits of each integer. Strategy: Extract digits from right (mod 10) and build reversed number (multiply by 10 + digit). O(log n) per number.");

    for i in 0..n {
        let mut num = arr[i];
        let mut reversed = 0i32;
        let original = num;
        while num > 0 {
            reversed = reversed * 10 + num % 10;
            num /= 10;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("{} -> {}", original, reversed),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], "All integers reversed".to_string());
    v.into_frames()
}

fn viz_math_ugly_number() -> Vec<VizFrame> {
    let n = 10;
    let mut ugly = vec![1i32; n];
    let mut v = VizLog::new(ugly.clone());
    v.ptrs(
        &[],
        &[],
        format!("Goal: Generate the first {} ugly numbers (only prime factors 2, 3, 5). Strategy: Three-pointer merge. Maintain pointers i2, i3, i5 into the ugly array. Next ugly = min(ugly[i2]*2, ugly[i3]*3, ugly[i5]*5).", n),
    );
    v.ptrs(
        &[(0, HighlightKind::Sorted)],
        &[(0, "i")],
        "ugly[0]=1".to_string(),
    );

    let mut i2 = 0usize;
    let mut i3 = 0usize;
    let mut i5 = 0usize;
    for i in 1..n {
        let next = (ugly[i2] * 2).min(ugly[i3] * 3).min(ugly[i5] * 5);
        ugly[i] = next;
        if next == ugly[i2] * 2 {
            i2 += 1;
        }
        if next == ugly[i3] * 3 {
            i3 += 1;
        }
        if next == ugly[i5] * 5 {
            i5 += 1;
        }
        v.array = ugly.clone();
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("ugly[{}]={} (p2={} p3={} p5={})", i, next, i2, i3, i5),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], format!("Ugly numbers: {:?}", ugly));
    v.into_frames()
}

fn viz_math_next_permutation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let n = rng.random_range(6..=8);
    let mut arr = rand_arr(&mut rng, n, 1, 9);
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Find the next lexicographically greater permutation. Strategy: Find rightmost ascent (a[i] < a[i+1]), swap a[i] with the smallest element > a[i] to its right, then reverse the suffix. Array: {:?}", arr));

    // Find rightmost ascent
    let mut i_opt: Option<usize> = None;
    for i in (0..n - 1).rev() {
        if arr[i] < arr[i + 1] {
            i_opt = Some(i);
            v.ptrs(
                &[(i, HighlightKind::Found)],
                &[(i, "i")],
                format!("Found ascent at {} ({}<{})", i, arr[i], arr[i + 1]),
            );
            break;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("[{}]={} >= [{}]={}, continue", i, arr[i], i + 1, arr[i + 1]),
        );
    }

    if let Some(i) = i_opt {
        // Find rightmost element > arr[i]
        for j in (i + 1..n).rev() {
            if arr[j] > arr[i] {
                v.ptrs(
                    &[(i, HighlightKind::Pivot), (j, HighlightKind::Active)],
                    &[(i, "i"), (j, "j")],
                    format!("Swap [{}]={} with [{}]={}", i, arr[i], j, arr[j]),
                );
                arr.swap(i, j);
                break;
            }
        }
        arr[i + 1..].reverse();
        v.array = arr.clone();
        let hl: Vec<_> = (i + 1..n).map(|x| (x, HighlightKind::Sorted)).collect();
        v.ptrs(&hl, &[], format!("Reverse suffix: {:?}", arr));
    } else {
        arr.reverse();
        v.array = arr.clone();
        v.ptrs(&[], &[], format!("Wrap around: {:?}", arr));
    }
    v.into_frames()
}

fn viz_math_modular_inverse() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let primes = [7, 11, 13];
    let p = primes[rng.random_range(0..primes.len())];
    let n = (p as usize).min(8);
    let arr: Vec<i32> = (1..=n as i32).collect();
    let mut v = VizLog::new(arr.clone());
    v.ptrs(&[], &[], format!("Goal: Compute modular inverse of each number mod {} (a prime). Strategy: By Fermat's little theorem, a^(-1) mod p = a^(p-2) mod p. Compute via binary exponentiation. O(log p) per inverse.", p));

    for i in 0..n {
        let a = arr[i] as i64;
        let m = p as i64;
        // Fermat: a^(p-2) mod p
        let mut result = 1i64;
        let mut base = a % m;
        let mut exp = m - 2;
        while exp > 0 {
            if exp % 2 == 1 {
                result = (result * base) % m;
            }
            base = (base * base) % m;
            exp /= 2;
        }
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("{}^(-1) mod {} = {}", a, p, result),
        );
    }
    let hl: Vec<_> = (0..n).map(|i| (i, HighlightKind::Sorted)).collect();
    v.ptrs(&hl, &[], "All modular inverses computed".to_string());
    v.into_frames()
}

fn viz_math_matrix_exponentiation() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let exp = rng.random_range(4..=8);
    let arr: Vec<i32> = vec![1, 1, 1, 0, 0, 0, 0, 0];
    let n = arr.len();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!("Goal: Compute Fibonacci({}) via matrix exponentiation. Strategy: [[1,1],[1,0]]^n gives fib(n) in top-left. Use binary exponentiation on 2x2 matrices. O(log n) matrix multiplications.", exp),
    );

    let mut a = [[1i64, 1], [1, 0]];
    let mut result = [[1i64, 0], [0, 1]];
    let mut e = exp;
    let mut step = 0;
    while e > 0 {
        let idx = step.min(n - 1);
        if e % 2 == 1 {
            let r00 = result[0][0] * a[0][0] + result[0][1] * a[1][0];
            let r01 = result[0][0] * a[0][1] + result[0][1] * a[1][1];
            let r10 = result[1][0] * a[0][0] + result[1][1] * a[1][0];
            let r11 = result[1][0] * a[0][1] + result[1][1] * a[1][1];
            result = [[r00, r01], [r10, r11]];
            v.ptrs(
                &[(idx, HighlightKind::Found)],
                &[(idx, "step")],
                format!("Multiply: result[0][0]={}", result[0][0]),
            );
        } else {
            v.ptrs(
                &[(idx, HighlightKind::Active)],
                &[(idx, "step")],
                format!("Square only, exp={}", e),
            );
        }
        let a00 = a[0][0] * a[0][0] + a[0][1] * a[1][0];
        let a01 = a[0][0] * a[0][1] + a[0][1] * a[1][1];
        let a10 = a[1][0] * a[0][0] + a[1][1] * a[1][0];
        let a11 = a[1][0] * a[0][1] + a[1][1] * a[1][1];
        a = [[a00, a01], [a10, a11]];
        e /= 2;
        step += 1;
    }
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: fib({}) = {}", exp, result[0][0]),
    );
    v.into_frames()
}

fn viz_math_chinese_remainder() -> Vec<VizFrame> {
    let mut rng = rand::rng();
    let mods = [3, 5, 7];
    let remainders: Vec<i32> = mods.iter().map(|&m| rng.random_range(0..m)).collect();
    let n = mods.len().min(8);
    let arr: Vec<i32> = mods.to_vec();
    let mut v = VizLog::new(arr);
    v.ptrs(
        &[],
        &[],
        format!(
            "CRT — x={}(mod {}), x={}(mod {}), x={}(mod {})",
            remainders[0], mods[0], remainders[1], mods[1], remainders[2], mods[2]
        ),
    );

    let product: i64 = mods.iter().map(|&m| m as i64).product();
    let mut result = 0i64;
    for i in 0..n {
        let mi = mods[i] as i64;
        let ni = product / mi;
        // Find inverse of ni mod mi
        let mut inv = 1i64;
        for candidate in 1..mi {
            if (ni * candidate) % mi == 1 {
                inv = candidate;
                break;
            }
        }
        let term = remainders[i] as i64 * ni * inv;
        result += term;
        v.ptrs(
            &[(i, HighlightKind::Active)],
            &[(i, "i")],
            format!("mod {}: N/m={} inv={} term={}", mods[i], ni, inv, term),
        );
    }
    result %= product;
    v.ptrs(
        &[(0, HighlightKind::Found)],
        &[(0, "i")],
        format!("Result: x = {} (mod {})", result, product),
    );
    v.into_frames()
}
